// Auto-generiert aus dem MeatyMunch Operations Manual Band 1 (12 Kapitel).
// Vollständiger Handbuch-Inhalt, strukturiert für die App.

export const handbookChapters = [{"no":"01","title":"Erscheinungsbild & Auftreten","thesis":"Der Gast entscheidet in Sekunden. Dein Erscheinungsbild ist die erste Aussage unserer Marke — noch bevor ein einziges Wort fällt.","readtime":"ca. 12 Minuten","sections":[{"index":"1.1","eyebrow":"Einführung","heading":"Du bist das Gesicht der Marke","blocks":[{"t":"lead","text":"Bei MeatyMunch verkaufen wir keine Burger. Wir verkaufen Vertrauen, Qualität und ein Erlebnis. Und das Erste, was der Gast von diesem Erlebnis sieht, bist du."},{"t":"p","text":"Bevor der Gast unser Essen probiert, sieht er, wie wir aussehen, wie wir uns bewegen und wie wir ihn begrüßen. Ein sauberes, gepflegtes und selbstbewusstes Auftreten sagt dem Gast in Sekunden: „Hier arbeiten Profis. Hier ist alles sauber. Hier bin ich richtig.\""},{"t":"p","text":"Dieses Kapitel legt fest, wie ein MeatyMunch-Mitarbeiter aussieht, auftritt und wirkt — an jedem Standort, in jeder Schicht, ohne Ausnahme. Nicht als Empfehlung, sondern als verbindlicher Standard."}]},{"index":"1.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"p","text":"Nach diesem Kapitel weißt du genau:"},{"t":"ul","items":["Wie ein MeatyMunch-Mitarbeiter aussieht — Kleidung, Haare, Hände, Hygiene.","Warum Erscheinungsbild über den ersten Eindruck des Gastes entscheidet.","Wann und wie du dich vor der Schicht einsatzbereit machst.","Wie du dich vor Gästen verhältst — Körpersprache, Ton, Handyregel.","Was passiert, wenn Standards nicht eingehalten werden."]}]},{"index":"1.3","eyebrow":"Warum das wichtig ist","heading":"Der erste Eindruck entscheidet","blocks":[{"t":"p","text":"Ein Gast entscheidet innerhalb weniger Sekunden, ob er uns vertraut. Diesen ersten Eindruck bekommen wir nie ein zweites Mal."},{"t":"p","text":"Jeder Mitarbeiter repräsentiert die Marke. Jeder Fleck auf der Schürze, jedes Handy in der Hand, jede unfreundliche Miene erzählt dem Gast eine Geschichte über uns — auch wenn kein Wort fällt. Deshalb ist Erscheinungsbild bei MeatyMunch keine Nebensache, sondern Teil des Produkts."}]},{"index":"1.4","eyebrow":"Unsere Standards","heading":"Der MeatyMunch-Dresscode","blocks":[{"t":"p","text":"Diese Standards gelten ausnahmslos, sobald du im Gastbereich oder in der Küche sichtbar bist."},{"t":"table","rows":[["Bereich","Standard","Nicht erlaubt"],["Arbeitskleidung","Saubere, gebügelte MeatyMunch-Kleidung, jede Schicht frisch. Farbe / Modell später ergänzen","Fleckige, zerknitterte oder private Straßenkleidung"],["Schürze","Saubere Schürze, korrekt gebunden, bei Verschmutzung sofort wechseln","Verschmutzte Schürze als „Putzlappen\" nutzen"],["Schuhe","Geschlossene, rutschfeste, saubere Schuhe Sicherheitsschuh-Pflicht prüfen","Offene Schuhe, Sandalen, verschmutzte Sneaker"],["Haare","Ordentlich; lange Haare zusammengebunden; Kopfbedeckung/Haarnetz nach Vorgabe","Offene lange Haare im Lebensmittelbereich"],["Bart","Gepflegt und getrimmt; bei Bedarf Bartnetz","Ungepflegter Bart ohne Schutz an offenen Lebensmitteln"],["Hände & Nägel","Sauber, kurz geschnitten, ungelackt; regelmäßiges Händewaschen","Lange Nägel, Nagellack, künstliche Nägel"],["Schmuck","Auf ein Minimum reduziert; keine losen Teile über Lebensmitteln","Auffällige Ringe, Armbänder, lange Ketten, Uhren am Handgelenk"],["Persönliche Hygiene","Frisch geduscht, dezenter Geruch, saubere Kleidung","Starkes Parfum, Körpergeruch, Rauchgeruch"],["Namensschild","Gut sichtbar getragen Design später ergänzen","Ohne Namensschild im Gastkontakt"]]}]},{"index":"1.5","eyebrow":"Schritt für Schritt","heading":"Die „Einsatzbereit\"-Routine vor der Schicht","blocks":[{"t":"p","text":"Pünktlich heißt bei MeatyMunch nicht „da sein\", sondern einsatzbereit sein. Diese Routine machst du jeden Tag in exakt dieser Reihenfolge."},{"t":"p","text":"01— 10 Min. vor SchichtbeginnRechtzeitig eintreffenDu bist spätestens 10 Minuten vor Schichtbeginn vor Ort — mit Puffer, nicht auf die Minute."},{"t":"p","text":"02UmziehenStraßenkleidung ablegen, frische MeatyMunch-Kleidung anziehen. Nie in Straßenkleidung an die Station."},{"t":"p","text":"03Haare & Bart richtenLange Haare zusammenbinden, Kopfbedeckung/Haarnetz aufsetzen, Bart bei Bedarf sichern."},{"t":"p","text":"04Hände gründlich waschenVor Arbeitsbeginn Hände nach Vorgabe waschen — Details siehe Kapitel Hygiene & Lebensmittelsicherheit."},{"t":"p","text":"05Schürze & NamensschildSaubere Schürze binden, Namensschild sichtbar anlegen."},{"t":"p","text":"06Einsatzbereit meldenKurzer Spiegel-Check, dann meldest du dich bei der Schichtleitung startklar."}]},{"index":"1.6","eyebrow":"Auftreten & Körpersprache","heading":"Wie wir wirken","blocks":[{"t":"p","text":"Erscheinungsbild endet nicht bei der Kleidung. Wie du stehst, schaust und sprichst, sendet dieselbe Botschaft."},{"t":"p","text":"Aufrechte Haltung, freundlicher Blickkontakt, ein echtes Lächeln. Der Gast wird begrüßt, bevor er fragen muss. Wir bedanken uns immer und verabschieden jeden Gast freundlich. Ruhe und Freundlichkeit gelten auch dann, wenn es stressig wird oder ein Gast schwierig ist."},{"t":"p","text":"Kein Anlehnen, keine verschränkten Arme, keine schlechte Laune vor Gästen. Keine privaten Gespräche, kein Lästern, keine Diskussionen im Gastbereich. Probleme werden nie vor dem Gast ausgetragen — sie werden ruhig und im Team gelöst."}]},{"index":"1.7","eyebrow":"Die Handyregel","heading":"Das Handy bleibt in der Tasche","blocks":[{"t":"box","label":"","text":"Verbindlich"},{"t":"p","text":"Während der Arbeit gilt: grundsätzlich kein privates Handy. Ein Mitarbeiter am Handy signalisiert dem Gast Desinteresse — und kostet uns Vertrauen."},{"t":"p","text":"Private Handynutzung ist ausschließlich in der Pause erlaubt. Ausnahmen nur für: betriebliche Nutzung, Anweisung durch den Chef oder einen Notfall."}]},{"index":"1.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Zwei Mitarbeiter, gleicher Container, gleicher Gast. Ein Bild sagt mehr als jede Regel."},{"t":"ul","items":["Fleckige Schürze vom Vortag","Offene lange Haare über der Theke","Handy in der Hand, kein Blickkontakt","Gast wird nicht begrüßt","Wirkung: unsauber, unprofessionell"]},{"t":"ul","items":["Frische, saubere Schürze","Haare gebunden, Namensschild sichtbar","Handy weg, offener Blickkontakt","„Herzlich willkommen bei MeatyMunch\"","Wirkung: sauber, professionell, vertrauenswürdig"]}]},{"index":"1.9","eyebrow":"Checkliste","heading":"Mein Erscheinungsbild — vor jeder Schicht","blocks":[{"t":"p","text":"Dein 30-Sekunden-Spiegel-Check, bevor du dich startklar meldest."},{"t":"ul","items":["Kleidung sauber, frisch und ordentlich","Schürze sauber und korrekt gebunden","Schuhe geschlossen, rutschfest und sauber","Haare zusammengebunden, Kopfbedeckung/Haarnetz sitzt","Hände gewaschen, Nägel kurz und sauber","Schmuck auf ein Minimum reduziert","Kein starkes Parfum, kein Körper- oder Rauchgeruch","Namensschild sichtbar angelegt","Handy in der Tasche — nicht am Arbeitsplatz"]}]},{"index":"1.10","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte & Verantwortung","blocks":[{"t":"p","text":"Standards, die niemand prüft, verschwinden. Deshalb ist Erscheinungsbild fester Teil der Schichtkontrolle."},{"t":"table","rows":[["Kontrollpunkt","Wer prüft","Wann"],["Erscheinungsbild & Kleidung","Schichtleitung","Bei Schichtbeginn"],["Hände & Nägel","Mitarbeiter (Eigenkontrolle)","Vor Arbeitsbeginn & laufend"],["Schürze sauber","Mitarbeiter & Schichtleitung","Laufend während der Schicht"],["Namensschild getragen","Schichtleitung","Bei Schichtbeginn"],["Auftreten am Gast","Schichtleitung","Stichprobe während Betrieb"]]},{"t":"box","label":"","text":"Was passiert bei Abweichung"},{"t":"p","text":"Kleine Abweichungen werden sofort und freundlich korrigiert (z. B. Schürze wechseln). Wiederholte Verstöße folgen dem Verhaltens- und Konsequenzrahmen aus Kapitel 11: Gespräch → schriftliche Verwarnung → Trennung. Hygieneverstöße wiegen dabei besonders schwer."}]},{"index":"1.11","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Der Gast sieht jeden Fleck. Bei Verschmutzung sofort wechseln — nicht bis zum Schichtende warten."},{"t":"p","text":"Es gibt kein „nur kurz\". In dem Moment sieht der Gast einen desinteressierten Betrieb. Handy weg."},{"t":"p","text":"Auf die Minute erscheinen und sich erst dann umziehen heißt: zu spät. Einsatzbereit ist der Standard."},{"t":"p","text":"Offene lange Haare im Lebensmittelbereich sind ein Hygieneverstoß — immer zusammenbinden."},{"t":"p","text":"Private Sorgen bleiben hinter der Theke. Vor dem Gast zählt Freundlichkeit — jeden Tag."},{"t":"p","text":"Starker Duft überlagert unser Essen und stört Gäste. Dezent und frisch ist der Standard."}]},{"index":"1.12","eyebrow":"Tipp vom Management","heading":"Best Practice","blocks":[{"t":"box","label":"","text":"Der Spiegel-Reflex"},{"t":"p","text":"Angewöhnen: Ein kurzer Blick in den Spiegel vor jeder Schicht — und ein zweiter nach der Pause. Frag dich in drei Sekunden: Würde ich mich selbst so bedienen lassen? Wer diese Frage jeden Tag mit „Ja\" beantwortet, trägt die Marke bereits im Kopf. Genau diese Menschen werden bei uns später Schichtleiter."}]},{"index":"1.13","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"box","label":"","text":"Kapitel 01 · Kernaussagen"},{"t":"ul","items":["Der Gast urteilt in Sekunden — dein Erscheinungsbild ist Teil des Produkts.","Saubere Kleidung, gebundene Haare, kurze Nägel, dezenter Duft — jede Schicht, ohne Ausnahme.","Pünktlich heißt einsatzbereit: 10 Minuten vorher, umgezogen, Hände gewaschen.","Das Handy bleibt in der Tasche — nur Pause, Notfall oder Anweisung.","Freundliches Auftreten und Blickkontakt gelten auch unter Stress."]},{"t":"box","label":"","text":"Schulungsvideo"},{"t":"p","text":"QR-Code zum kurzen Onboarding-Clip „Erscheinungsbild & Auftreten\". Link später ergänzen"}]}]},{"no":"02","title":"Organisation, Rollen & Verantwortlichkeiten","thesis":"Jeder weiß, was seine Aufgabe ist — und wer worüber entscheidet. So läuft der Betrieb sauber, auch wenn der Inhaber nicht da ist.","readtime":"ca. 14 Minuten","sections":[{"index":"2.1","eyebrow":"Einführung","heading":"Klare Rollen, klarer Betrieb","blocks":[{"t":"lead","text":"Ein Betrieb funktioniert nicht, weil alle „irgendwie mithelfen\", sondern weil jeder genau weiß, wofür er verantwortlich ist."},{"t":"p","text":"Bei MeatyMunch arbeitet niemand nach Gefühl oder Zuruf. Jede Rolle hat klare Aufgaben, klare Grenzen und einen klaren Ansprechpartner. Das verhindert Chaos in der Stoßzeit, vermeidet Fehler und sorgt dafür, dass Aufgaben nicht liegen bleiben, weil „jemand anderes\" sie machen sollte."},{"t":"p","text":"Dieses Prinzip ist die Grundlage unserer Skalierung: Nur wenn Rollen unabhängig von einzelnen Personen definiert sind, kann jeder neue Standort denselben Ablauf haben — vom Container bis zum 100. Restaurant."}]},{"index":"2.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel weißt","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Wer im Team welche Rolle hat — und wie das Organigramm aufgebaut ist.","Was von deiner Rolle konkret erwartet wird.","Wer worüber entscheidet und wann du eskalierst.","Wie Verantwortung pro Schicht und Station verteilt ist.","Welchen Weg es vom Mitarbeiter bis zum Franchise-Partner gibt."]}]},{"index":"2.3","eyebrow":"Warum das wichtig ist","heading":"Verantwortung ohne Lücken","blocks":[{"t":"p","text":"Wenn eine Aufgabe niemandem klar zugeordnet ist, passiert eines von zwei Dingen: Sie wird doppelt gemacht — oder gar nicht. Beides kostet Zeit, Geld und Qualität."},{"t":"p","text":"Klare Rollen bedeuten: Jeder Handgriff hat einen Verantwortlichen. Fehler werden schneller erkannt, Entscheidungen fallen schneller, und der Gast merkt nichts von interner Unklarheit. Genau das unterscheidet einen Profibetrieb von einer Imbissbude."},{"t":"box","label":"","text":"Grundregel"},{"t":"p","text":"Jede Aufgabe hat genau einen Verantwortlichen. „Das macht schon irgendwer\" gibt es bei MeatyMunch nicht."}]},{"index":"2.4","eyebrow":"Das Organigramm","heading":"So ist der Standort aufgebaut","blocks":[{"t":"p","text":"Aktuelle Struktur am Standort Container. Mit wachsender Größe kommen weitere Ebenen dazu (siehe Abschnitt 2.9)."}]},{"index":"2.5","eyebrow":"Rollen im Detail","heading":"Wer wofür verantwortlich ist","blocks":[{"t":"p","text":"„Ich liefere an meiner Station perfekte Qualität — nach Standard, nicht nach Gefühl.\""},{"t":"ul","items":["Arbeitet an der zugewiesenen Station nach SOP","Hält Sauberkeit & Hygiene durchgehend ein","Begrüßt und bedient Gäste freundlich","Meldet Fehler und Engpässe sofort","Hinterlässt den Arbeitsplatz sauberer als vorgefunden"]},{"t":"p","text":"„Ich sorge dafür, dass die Schicht läuft wie im Handbuch — und gehe voran.\""},{"t":"ul","items":["Führt Öffnungs- & Schließablauf durch","Teilt Stationen ein und behält den Überblick","Kontrolliert Qualität, Sauberkeit & Erscheinungsbild","Löst Probleme im Betrieb und am Gast","Übergibt die Schicht sauber & dokumentiert"]},{"t":"p","text":"„Ich führe den gesamten Standort — Zahlen, Team und Standards.\""},{"t":"ul","items":["Verantwortet Umsatz, Kosten & Personal des Standorts","Führt und entwickelt die Schichtleiter","Sichert Marken- & Qualitätsstandards","Verantwortet Bestellung, Inventur & Compliance"]},{"t":"p","text":"„Ich definiere, wofür MeatyMunch steht — und schütze diesen Standard.\""},{"t":"ul","items":["Setzt Vision, Werte & Standards","Verantwortet Finanzen, Einkauf & Rezepturen","Trifft strategische Entscheidungen","Entwickelt Menschen zu Führungskräften"]}]},{"index":"2.6","eyebrow":"Schichtmodell & Zeiten","heading":"Wann wer arbeitet","blocks":[{"t":"p","text":"Öffnungszeiten: Montag bis Samstag, 10:30–20:00 Uhr. Die Vorbereitung (Prep) beginnt vorher."},{"t":"table","rows":[["Zeitfenster","Uhrzeit","Fokus"],["Prep / Vorbereitung","ab 09:30","Station vorbereiten, Ware, Sauberkeit, Öffnungsablauf"],["Schicht 1","11:30 – 19:30","Betrieb, Mittags- & Nachmittagsgeschäft"],["Schicht 2","16:30 – 20:30","Abendgeschäft, Schließablauf & Reinigung"]]},{"t":"box","label":"","text":"Erinnerung"},{"t":"p","text":"Schichtbeginn heißt einsatzbereit, nicht „ankommen\". Details siehe Kapitel 01 — die „Einsatzbereit\"-Routine."}]},{"index":"2.7","eyebrow":"Entscheidungswege","heading":"Wer entscheidet was — der Eskalationsweg","blocks":[{"t":"p","text":"Bei einem Problem gilt immer dieselbe Reihenfolge. Löse auf der niedrigsten Stufe, auf der es geht — eskaliere erst, wenn deine Kompetenz endet."},{"t":"p","text":"Alles, was in deiner Station & deinem Standard steht, löst du eigenständig — z. B. Schürze wechseln, Ware nachfüllen, Gast freundlich bedienen."},{"t":"p","text":"Bei Unklarheit, Gastbeschwerde oder Störung im Ablauf informierst du sofort den Schichtleiter. Er entscheidet und koordiniert."},{"t":"p","text":"Größere Themen — z. B. Sicherheit, Technikausfall, Personal, Geld, Rezeptur — gehen an die Geschäftsführung. Details siehe Kapitel Notfälle."},{"t":"box","label":"","text":"Ausnahme"},{"t":"p","text":"Bei Gefahr für Gesundheit oder Sicherheit gilt kein Stufenweg: sofort handeln und sofort melden."}]},{"index":"2.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Stoßzeit, ein Gast beschwert sich über eine kalte Portion Pommes."},{"t":"ul","items":["Jeder schaut den anderen an","Niemand fühlt sich zuständig","Der Gast wartet und wird lauter","Es wird vor dem Gast diskutiert"]},{"t":"ul","items":["Mitarbeiter meldet sofort dem Schichtleiter","Schichtleiter entschuldigt sich beim Gast","Frische Portion wird sofort zubereitet","Problem gelöst statt diskutiert"]}]},{"index":"2.9","eyebrow":"Skalierung","heading":"Wie die Struktur mitwächst","blocks":[{"t":"p","text":"Dieselbe Logik trägt vom Container bis zur Kette — es kommen nur Ebenen dazu, die Rollen bleiben klar."},{"t":"p","text":"Inhaber führt direkt, mit Schichtleiter & Team."},{"t":"p","text":"Restaurantleiter übernimmt den Standort."},{"t":"p","text":"Gebiets-/Bereichsleitung koordiniert Standorte."},{"t":"p","text":"Franchise-Partner führen nach demselben Handbuch."}]},{"index":"2.10","eyebrow":"Checkliste","heading":"Kenne ich meine Rolle?","blocks":[{"t":"ul","items":["Ich weiß, welche Station ich in dieser Schicht verantworte","Ich kenne meinen direkten Ansprechpartner (Schichtleiter)","Ich weiß, was ich selbst entscheiden darf und was nicht","Ich weiß, wann ich ein Problem eskaliere","Ich kenne die Schichtzeiten und bin einsatzbereit","Ich melde Fehler & Engpässe sofort, nicht später"]}]},{"index":"2.11","eyebrow":"Qualitätskontrolle","heading":"Verantwortung pro Station","blocks":[{"t":"p","text":"In jeder Schicht ist jede Station klar zugeordnet — kein Bereich bleibt ohne Verantwortlichen."},{"t":"table","rows":[["Verantwortungsbereich","Verantwortlich","Kontrolle durch"],["Station / Produktqualität","Zugeteilter Mitarbeiter","Schichtleiter"],["Sauberkeit & Hygiene","Alle im Bereich","Schichtleiter"],["Öffnungs- & Schließablauf","Schichtleiter","Inhaber / GF"],["Kasse & Gast","Zugeteilter Mitarbeiter","Schichtleiter"],["Standard & Rezeptur","Inhaber / Geschäftsführung","MeatyMunch-Standard"]]}]},{"index":"2.12","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Wenn niemand klar zuständig ist, bleibt es liegen. Im Zweifel: nachfragen, wer verantwortlich ist."},{"t":"p","text":"Große Entscheidungen gehören nicht auf die eigene Station. Halte den Eskalationsweg ein."},{"t":"p","text":"Fehler und Engpässe sofort melden — nicht bis Schichtende warten, bis es teuer wird."},{"t":"p","text":"Zuständigkeiten werden nie vor dem Gast geklärt. Ruhig lösen, intern klären."}]},{"index":"2.13","eyebrow":"Tipp vom Management","heading":"Best Practice — dein Weg nach oben","blocks":[{"t":"box","label":"","text":"Vom Team zum Partner"},{"t":"p","text":"Wir befördern von innen. Wer seine Rolle zuverlässig ausfüllt, Verantwortung übernimmt und Standards lebt, wird bei uns Schichtleiter — später Restaurantleiter und perspektivisch Franchise-Partner. Nicht der Lauteste steigt auf, sondern der Verlässlichste. Zeig, dass man dir Verantwortung geben kann, dann bekommst du sie."}]},{"index":"2.14","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Jede Aufgabe hat genau einen Verantwortlichen — „irgendwer\" gibt es nicht.","Struktur: Inhaber → Schichtleiter → Team, mit klaren Rollen.","Eskaliere in Stufen: selbst lösen → Schichtleiter → Geschäftsführung.","Bei Gefahr gilt kein Stufenweg — sofort handeln und melden.","Rollen sind skalierbar: dieselbe Logik vom Container bis zur Kette."]},{"t":"p","text":"QR-Code zum aktuellen Organigramm & Rollenübersicht. Link später ergänzen"}]}]},{"no":"03","title":"Hygiene & Lebensmittelsicherheit","thesis":"Sauberkeit ist bei uns keine Aufgabe, sondern ein Standard. Sie schützt unsere Gäste, unsere Marke — und unsere Halal-Integrität.","readtime":"ca. 16 Minuten","sections":[{"index":"3.1","eyebrow":"Einführung","heading":"Sauberkeit ist ein Standard","blocks":[{"t":"lead","text":"Geputzt wird nicht nur abends. Während der gesamten Schicht wird sauber gearbeitet — jeder hinterlässt seinen Arbeitsplatz sauberer, als er ihn vorgefunden hat."},{"t":"p","text":"Lebensmittelsicherheit ist der eine Bereich, in dem es keine Toleranz gibt. Ein Fehler an der Kasse kostet Geld. Ein Fehler bei der Hygiene kostet die Gesundheit eines Gastes und das Vertrauen in unsere Marke."},{"t":"p","text":"Dieses Kapitel fasst die Grundregeln zusammen, die jeder MeatyMunch-Mitarbeiter beherrschen muss. Grundlage ist das HACCP-Prinzip und die gesetzliche Belehrung nach §43 Infektionsschutzgesetz."},{"t":"box","label":"","text":"Voraussetzung"},{"t":"p","text":"Vor dem ersten Arbeitstag im Lebensmittelbereich ist eine Belehrung nach §43 IfSG (Gesundheitszeugnis) Pflicht. Ohne sie darf niemand an Lebensmitteln arbeiten. Nachweis in Personalakte"}]},{"index":"3.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel beherrschst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Wann und wie du deine Hände richtig wäschst.","Welche Temperaturen für Kühlen und Warmhalten gelten.","Wie FIFO und Beschriftung im Alltag funktionieren.","Wie du Kreuzkontamination und Halal-Verstöße verhinderst.","Was laufend kontrolliert und dokumentiert wird."]}]},{"index":"3.3","eyebrow":"Warum das wichtig ist","heading":"Vier Dinge stehen auf dem Spiel","blocks":[{"t":"p","text":"Falsch gelagerte Lebensmittel können Gäste krank machen. Das darf nie passieren."},{"t":"p","text":"Eine schlechte Hygiene-Meldung zerstört Vertrauen, das wir jahrelang aufbauen."},{"t":"p","text":"Die Behörde kontrolliert. Verstöße bedeuten Bußgeld oder Schließung."},{"t":"p","text":"Kreuzkontamination gefährdet unsere Halal-Integrität — unsere wichtigste Überzeugung."}]},{"index":"3.4","eyebrow":"Händehygiene","heading":"Deine Hände sind Werkzeug Nummer 1","blocks":[{"t":"table","rows":[["Vor Arbeitsbeginn","Immer, bevor du an die Station gehst"],["Nach der Toilette","Ausnahmslos, gründlich"],["Nach dem Müll","Nach jedem Kontakt mit Abfall"],["Nach rohem Fleisch","Bevor du etwas anderes anfasst"],["Vor Handschuhwechsel","Vor dem Anziehen frischer Handschuhe"]]},{"t":"p","text":"01Warmes WasserAnfeuchten & einseifenHände nass machen, Seife gründlich verteilen."},{"t":"p","text":"02mind. 20 SekundenGründlich reibenHandflächen, Rücken, Zwischenräume, Daumen, Fingerspitzen und Nägel."},{"t":"p","text":"03AbspülenSeife vollständig unter fließendem Wasser entfernen."},{"t":"p","text":"04AbtrocknenMit Einweg-Küchenrolle abtrocknen — nie am Kleidungsstück oder Handtuch."}]},{"index":"3.5","eyebrow":"Temperatur & Kühlkette","heading":"Die Gefahrenzone kennen","blocks":[{"t":"p","text":"Bakterien vermehren sich am schnellsten im mittleren Temperaturbereich. Lebensmittel gehören entweder kalt oder heiß — nie lange dazwischen."},{"t":"table","rows":[["Bereich","Richtwert","Hinweis"],["Kühlware allgemein","≤ +7 °C","Salat, Käse, Soßen, offene Ware"],["Hackfleisch","≤ +2 °C","Besonders empfindlich, streng kühlen"],["Geflügel (roh)","≤ +4 °C","Getrennt von anderer Ware lagern"],["Tiefkühlware","≤ −18 °C","Durchgehende Kühlkette halten"],["Warmhalten","≥ +65 °C","Curry-Soße, Bain-Marie, warme Ware"],["Geflügel durchgegart","≥ +72 °C Kern","Chicken immer vollständig durchgaren"]]},{"t":"box","label":"","text":"Regel"},{"t":"p","text":"Kühlkette nie unterbrechen. Ware nicht unnötig lange offen stehen lassen. Im Zweifel: Schichtleiter fragen, nicht raten."}]},{"index":"3.6","eyebrow":"FIFO & Beschriftung","heading":"First In, First Out","blocks":[{"t":"p","text":"FIFO bedeutet: Was zuerst geliefert wurde, wird zuerst verbraucht. So wird nichts alt und nichts verschwendet."},{"t":"p","text":"01Neue Ware nach hintenFrische Lieferung immer hinter die ältere Ware räumen."},{"t":"p","text":"02Ältere Ware nach vorneWas zuerst weg muss, steht griffbereit vorne."},{"t":"p","text":"03BeschriftenAngebrochene & vorbereitete Ware mit Datum kennzeichnen. Etiketten-Standard später ergänzen"},{"t":"p","text":"04PrüfenVor Verwendung Datum & Aussehen kontrollieren. Im Zweifel entsorgen."}]},{"index":"3.7","eyebrow":"Auftauen & Trennung","heading":"Auftauen & Kreuzkontamination","blocks":[{"t":"p","text":"Aufgetaut wird ausschließlich im Kühlschrank — nie bei Raumtemperatur, nie im Waschbecken. Aufgetaute Ware nicht wieder einfrieren."},{"t":"p","text":"Rohes Fleisch nie mit fertiger Ware, Salat oder Brot in Kontakt bringen. Getrennte Arbeitsbereiche, getrennte Werkzeuge, Hände & Handschuhe zwischendurch wechseln."},{"t":"box","label":"","text":"Halal ohne Kompromisse"},{"t":"p","text":"Alle Produkte sind halal: kein Schweinefleisch, kein Alkohol, keine alkoholhaltigen Produkte. Kreuzkontamination gefährdet nicht nur die Hygiene, sondern unsere Halal-Integrität. Halal ist bei MeatyMunch kein Marketing — es ist unsere Überzeugung."}]},{"index":"3.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Rohes Chicken wird für die nächste Charge vorbereitet."},{"t":"ul","items":["Gleiches Brett für Fleisch und Salat","Hände nach rohem Fleisch nicht gewaschen","Ware bei Raumtemperatur aufgetaut","Keine Datumskennzeichnung"]},{"t":"ul","items":["Getrennte Bereiche & Werkzeuge","Hände gewaschen, Handschuhe gewechselt","Im Kühlschrank aufgetaut","Mit Datum beschriftet, FIFO eingehalten"]}]},{"index":"3.9","eyebrow":"Checkliste","heading":"Hygiene-Check der Schicht","blocks":[{"t":"ul","items":["Hände zu allen Pflicht-Zeitpunkten gewaschen","Handschuhe sauber und rechtzeitig gewechselt","Kühl- und Warmhalte-Temperaturen im Richtwert","FIFO eingehalten — alte Ware zuerst","Vorbereitete Ware mit Datum beschriftet","Rohes Fleisch getrennt von fertiger Ware","Aufgetaut nur im Kühlschrank","Arbeitsflächen laufend gereinigt (clean as you go)"]}]},{"index":"3.10","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte & Dokumentation","blocks":[{"t":"p","text":"Kontrollierte Hygiene ist gelebte Hygiene. Diese Punkte werden regelmäßig geprüft und — wo nötig — dokumentiert."},{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Kühltemperaturen","Schichtleiter","Bei Öffnung & Schließung Temperaturliste ergänzen"],["Warmhaltetemperatur","Zuständiger Mitarbeiter","Laufend während Betrieb"],["Händehygiene","Mitarbeiter (Eigenkontrolle)","Zu allen Pflicht-Zeitpunkten"],["FIFO & Beschriftung","Mitarbeiter & Schichtleiter","Bei Warenannahme & Prep"],["Sauberkeit Flächen","Alle","Laufend & beim Schließablauf"]]}]},{"index":"3.11","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Bei Raumtemperatur wächst genau das, was wir verhindern wollen. Nur im Kühlschrank auftauen."},{"t":"p","text":"Handschuhe ersetzen kein Händewaschen. Vor dem Anziehen immer Hände waschen."},{"t":"p","text":"Ohne Datum ist das nur geraten. Beschriften und im Zweifel entsorgen."},{"t":"p","text":"Rohes Fleisch und fertige Ware nie auf derselben Fläche. Bereiche trennen."},{"t":"p","text":"Jede Minute offen schwächt die Kühlkette. Schnell arbeiten, sofort schließen."},{"t":"p","text":"Sauber wird während der ganzen Schicht gearbeitet — nicht erst abends."}]},{"index":"3.12","eyebrow":"Tipp vom Management","heading":"Best Practice — Clean as you go","blocks":[{"t":"box","label":"","text":"Die Zwei-Minuten-Regel"},{"t":"p","text":"Wenn eine Reinigung weniger als zwei Minuten dauert, mach sie sofort — nicht später. Wer laufend sauber arbeitet, hat abends kaum Arbeit und nie eine böse Überraschung bei der Kontrolle. Sauberkeit während der Schicht ist immer leichter als danach."}]},{"index":"3.13","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Hände waschen zu allen Pflicht-Zeitpunkten — Handschuhe ersetzen das nicht.","Lebensmittel kalt oder heiß — nie lange in der Gefahrenzone.","FIFO & Datum: alte Ware zuerst, alles beschriftet.","Auftauen nur im Kühlschrank, rohes Fleisch immer getrennt.","Keine Kreuzkontamination — sie schützt Gesundheit und Halal-Integrität."]},{"t":"p","text":"QR-Code zu Temperaturprotokoll & Reinigungsplan. Link später ergänzen"}]}]},{"no":"04","title":"Öffnungs- & Schließablauf","thesis":"Jeder Tag beginnt und endet gleich — nach Plan, nicht nach Zufall. So erlebt der Gast dieselbe Qualität, egal wer Schicht hat.","readtime":"ca. 15 Minuten","sections":[{"index":"4.1","eyebrow":"Einführung","heading":"Der Tag hat einen Rhythmus","blocks":[{"t":"lead","text":"Ein guter Tag entsteht nicht zufällig. Er beginnt mit einer sauberen Öffnung und endet mit einer sauberen Schließung — dazwischen läuft der Betrieb rund."},{"t":"p","text":"Öffnung und Schließung sind die zwei wichtigsten Routinen des Tages. Werden sie sauber gemacht, startet die nächste Schicht ohne Chaos und der Gast merkt nie, dass gerade gewechselt wurde. Werden sie geschludert, zieht sich der Fehler durch den ganzen Tag."}]},{"index":"4.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Den Öffnungsablauf Schritt für Schritt selbstständig durchführen.","Die Stationen kennen und wissen, wo die SOP-Karte gilt.","Eine saubere Schichtübergabe machen.","Den Schließablauf vollständig und ohne Lücken abschließen."]},{"t":"box","label":"","text":"Wichtig"},{"t":"p","text":"Die genauen Abläufe an Grill, Fritteuse & Co. stehen auf den laminierten SOP-Karten (SOP 1–11) und den Burger-Build-Karten (SOP 01–11). Dieses Kapitel ersetzt sie nicht — es ordnet sie in den Tagesablauf ein."}]},{"index":"4.3","eyebrow":"Warum das wichtig ist","heading":"Gleicher Ablauf, gleiche Qualität","blocks":[{"t":"p","text":"Der Gast soll in jeder Schicht dasselbe Erlebnis haben — unabhängig davon, wer geöffnet oder geschlossen hat. Genau deshalb folgt jeder demselben Ablauf, nicht seiner eigenen Erinnerung."},{"t":"p","text":"Ein sauberer Schließablauf ist außerdem die halbe Öffnung: Wer abends alles richtig zurücklässt, spart dem Morgenteam Zeit und startet den nächsten Tag ohne Rückstand."}]},{"index":"4.4","eyebrow":"Öffnungsablauf","heading":"Von 09:30 bis zum ersten Gast","blocks":[{"t":"p","text":"Verbindliche Checkliste an der Wand: SOP 01 — Öffnung."},{"t":"p","text":"01ab 09:30Ankommen & einsatzbereitUmgezogen, Hände gewaschen, Erscheinungsbild geprüft (siehe Kapitel 01)."},{"t":"p","text":"02Technik & Geräte einschaltenLicht, Strom, Geräte. Fritteuse und Grill rechtzeitig vorheizen. Geräteliste ergänzen"},{"t":"p","text":"03Temperaturen prüfenKühl- und Warmhalte-Temperaturen kontrollieren und notieren (siehe Kapitel 03)."},{"t":"p","text":"04Stationen vorbereitenWare nach MIN/MAX auffüllen, Soßen & Prep bereitstellen — Details je Station siehe SOP-Karte."},{"t":"p","text":"05Sauberkeit final checkenAlle Flächen und Arbeitsplätze sauber und einsatzbereit."},{"t":"p","text":"06Kasse vorbereitenWechselgeld prüfen, Kasse startklar (siehe Kassenbuch)."},{"t":"p","text":"0710:30ÖffnenBereit für den ersten Gast — freundlich, sauber, vollständig."}]},{"index":"4.5","eyebrow":"Stationen im Überblick","heading":"Wo was passiert","blocks":[{"t":"p","text":"Jede Station hat ihre eigene, laminierte SOP-Karte als verbindliche Anleitung. Hier die Zuordnung im Überblick:"},{"t":"p","text":"Ware, Soßen & Zutaten vorbereiten, MIN/MAX auffüllen."},{"t":"p","text":"Classic Smash & Chilli Milli nach Build-Karte."},{"t":"p","text":"Chicken & frittierte Produkte nach SOP."},{"t":"p","text":"Pommes & Loaded Fries nach Standard."},{"t":"p","text":"Curry-Soße & warme Soßen warmhalten."},{"t":"p","text":"Bestellung, Packen, Gast & Kasse."}]},{"index":"4.6","eyebrow":"Schichtübergabe","heading":"Sauber übergeben um 16:30","blocks":[{"t":"p","text":"Beim Wechsel von Schicht 1 auf Schicht 2 wird nicht nur die Station übergeben, sondern auch das Wissen. Kurz, klar, vollständig."},{"t":"table","rows":[["Was wird übergeben","Warum"],["Warenstand & Engpässe","Damit nichts ausgeht und rechtzeitig nachbereitet wird"],["Offene Bestellungen","Damit Lieferungen & Bestellfristen nicht vergessen werden"],["Reinigungsstand","Damit klar ist, was noch zu tun ist"],["Besondere Vorkommnisse","Gastthemen, Technik, Reklamationen"],["Kassenstand","Für einen sauberen Abschluss am Abend"]]}]},{"index":"4.7","eyebrow":"Schließablauf","heading":"Von 20:00 bis abgeschlossen","blocks":[{"t":"p","text":"Verbindliche Checklisten: SOP 02 — Schließung & SOP 03 — Spezialreinigung (feste Sonderaufgaben nach Wochentagen)."},{"t":"p","text":"0120:00Öffnungszeit-EndeLetzte Bestellungen abarbeiten, keine neue Ware mehr anbraten als nötig."},{"t":"p","text":"02Geräte herunterfahrenGrill & Fritteuse nach SOP ausschalten und abkühlen lassen, Öl-Handling nach Vorgabe."},{"t":"p","text":"03Ware sichernFIFO, beschriften, kühlen oder entsorgen (siehe Kapitel 03). Nichts offen stehen lassen."},{"t":"p","text":"04Stationen reinigenAlle Flächen, Geräte & Werkzeuge gründlich reinigen (siehe Reinigungsplan)."},{"t":"p","text":"05Müll & BödenMüll raus, Böden wischen, Bereich aufräumen."},{"t":"p","text":"06KassenabschlussKasse zählen, Abschluss machen, im Kassenbuch eintragen (siehe Kassenbuch)."},{"t":"p","text":"07Temperaturen & KühlungKühltemperaturen final prüfen, Kühlung gesichert."},{"t":"p","text":"08Abschließen & übergebenAlles aus, Strom/Sicherheit prüfen, abschließen. Offene Punkte für den nächsten Tag notieren."}]},{"index":"4.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Das Morgenteam öffnet den Container."},{"t":"ul","items":["Flächen nicht gereinigt","Ware nicht beschriftet, FIFO unklar","Kein Wechselgeld vorbereitet","Morgens 30 Min. Rückstand vor Öffnung"]},{"t":"ul","items":["Alles sauber & einsatzbereit","Ware beschriftet, FIFO klar","Kasse vorbereitet","Öffnung läuft pünktlich & entspannt"]}]},{"index":"4.9","eyebrow":"Checklisten","heading":"Öffnung & Schließung zum Abhaken","blocks":[{"t":"ul","items":["Einsatzbereit & umgezogen","Geräte an, Grill/Fritteuse vorgeheizt","Temperaturen geprüft & notiert","Stationen nach MIN/MAX aufgefüllt","Flächen sauber & einsatzbereit","Kasse & Wechselgeld bereit"]},{"t":"ul","items":["Geräte aus & abgekühlt","Ware gesichert, FIFO & beschriftet","Stationen & Flächen gereinigt","Müll raus, Böden gewischt","Kassenabschluss im Kassenbuch","Temperaturen ok, abgeschlossen"]}]},{"index":"4.10","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Öffnung vollständig","Schichtleiter","Vor 10:30"],["Übergabe dokumentiert","Beide Schichtleiter","16:30"],["Schließung vollständig","Schichtleiter","Nach 20:00"],["Kassenabschluss stimmt","Schichtleiter","Beim Schließen"],["Kühlung final gesichert","Schichtleiter","Vor Verlassen"]]}]},{"index":"4.11","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Wer erst um 10:15 anfängt, öffnet gehetzt. Prep beginnt um 09:30."},{"t":"p","text":"Der erste Gast wartet unnötig. Geräte rechtzeitig hochfahren."},{"t":"p","text":"Halbe Infos führen zu Fehlern in Schicht 2. Vollständig übergeben."},{"t":"p","text":"Das Morgenteam startet dann im Rückstand. Abends fertig machen."},{"t":"p","text":"Fehlende Einträge machen Zahlen unbrauchbar. Immer ins Kassenbuch."},{"t":"p","text":"Über Nacht kippt sonst Ware. Vor dem Abschließen prüfen."}]},{"index":"4.12","eyebrow":"Tipp vom Management","heading":"Best Practice — Schließen für das Morgenteam","blocks":[{"t":"box","label":"","text":"Denk an die Kollegen"},{"t":"p","text":"Schließe den Container so, wie du ihn morgens gerne vorfinden würdest. Ein sauberer, aufgefüllter, beschrifteter Arbeitsplatz ist das beste Geschenk an das nächste Team — und der schnellste Weg zu einer pünktlichen, entspannten Öffnung. Gute Schließung ist gelebte Teamarbeit."}]},{"index":"4.13","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Prep ab 09:30, Öffnung 10:30 — pünktlich und vollständig.","Jede Station folgt ihrer SOP-Karte — dieses Kapitel ordnet sie ein.","Übergabe um 16:30: Ware, Bestellungen, Reinigung, Vorkommnisse, Kasse.","Schließung vollständig: reinigen, sichern, abschließen, Kasse.","Saubere Schließung = entspannte Öffnung am nächsten Tag."]},{"t":"p","text":"QR-Code zu den druckbaren Öffnungs-/Schließ-Checklisten & SOP-Karten. Link später ergänzen"}]}]},{"no":"05","title":"Kommunikation, Verhalten & Premium-Service","thesis":"Der Gast bezahlt unser Gehalt. Jede Begegnung ist eine Chance, aus einem Gast einen Stammgast zu machen.","readtime":"ca. 14 Minuten","sections":[{"index":"5.1","eyebrow":"Einführung","heading":"Service ist Teil des Produkts","blocks":[{"t":"lead","text":"Ohne Gäste gibt es keine Arbeitsplätze. Deshalb behandeln wir jeden Gast mit Respekt — auch schwierige Gäste."},{"t":"p","text":"Ein perfekter Burger verliert seinen Wert, wenn der Gast unfreundlich behandelt wird. Umgekehrt kommt ein Gast, der sich willkommen fühlt, gerne wieder — und bringt andere mit. Service ist bei MeatyMunch kein „Nettsein nebenbei\", sondern ein fester Standard wie Sauberkeit und Qualität."},{"t":"box","label":"","text":"Unser Serviceprinzip"},{"t":"p","text":"Der Gast steht immer im Mittelpunkt. Probleme werden gelöst, nicht diskutiert."}]},{"index":"5.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Jeden Gast entlang des Servicebogens souverän betreuen.","Freundlich, respektvoll und professionell kommunizieren.","Mit Beschwerden und schwierigen Gästen ruhig umgehen.","Im Team respektvoll und offen kommunizieren."]}]},{"index":"5.3","eyebrow":"Warum das wichtig ist","heading":"Der Gast entscheidet über alles","blocks":[{"t":"p","text":"Ein zufriedener Gast kommt wieder und empfiehlt uns weiter. Ein schlecht behandelter Gast kommt nie wieder — und erzählt es zehn anderen. Guter Service ist damit die günstigste und stärkste Werbung, die wir haben."},{"t":"p","text":"Gerade als wachsende Marke leben wir von Vertrauen. Jede freundliche Begegnung zahlt darauf ein, jede unfreundliche zieht davon ab."}]},{"index":"5.4","eyebrow":"Der Servicebogen","heading":"Jede Gastbegegnung in vier Phasen","blocks":[{"t":"p","text":"Vom ersten Blickkontakt bis zur Verabschiedung folgt jede Interaktion demselben Bogen."},{"t":"p","text":"01BegrüßenBlickkontakt, Lächeln, freundlicher Gruß — bevor der Gast fragen muss.„Herzlich willkommen bei MeatyMunch! Was darf es sein?\""},{"t":"p","text":"02AufnehmenAufmerksam zuhören, bei Bedarf freundlich beraten, Bestellung wiederholen.„Gerne — einmal Classic Smash, kommt sofort.\""},{"t":"p","text":"03AusgebenBestellung vollständig & sauber übergeben, kurz prüfen, ob alles dabei ist.„Vielen Dank — hier ist Ihre Bestellung. Lassen Sie es sich schmecken!\""},{"t":"p","text":"04VerabschiedenJeden Gast freundlich verabschieden — der letzte Eindruck bleibt.„Danke für Ihren Besuch, bis zum nächsten Mal!\""}]},{"index":"5.5","eyebrow":"Wie wir sprechen","heading":"Unsere Kommunikationsstandards","blocks":[{"t":"p","text":"Vier Worte beschreiben, wie wir mit Gästen und untereinander sprechen: freundlich, respektvoll, direkt, professionell."},{"t":"ul","items":["Freundlicher Ton, klare Worte","Blickkontakt und Lächeln","„Bitte\" und „Danke\" sind Standard","Ruhe bewahren, auch unter Stress"]},{"t":"ul","items":["Beleidigungen oder Anschreien","Diskussionen vor Gästen","Lästern über Gäste oder Kollegen","Schlechte Laune am Gast auslassen"]}]},{"index":"5.6","eyebrow":"Schwierige Gäste & Reklamationen","heading":"Ruhig bleiben, lösen, gewinnen","blocks":[{"t":"p","text":"Eine Beschwerde ist kein Angriff, sondern eine Chance: Wer ein Problem gut löst, gewinnt oft einen treueren Gast als vorher. Folge immer diesen vier Schritten."},{"t":"p","text":"01ZuhörenAusreden lassen, nicht unterbrechen, ernst nehmen. Der Gast will gehört werden."},{"t":"p","text":"02Verstehen & entschuldigenKurz zusammenfassen, sich für die Unannehmlichkeit entschuldigen — ohne Ausreden."},{"t":"p","text":"03LösenSchnell eine Lösung anbieten (z. B. frische Portion). Bei Unsicherheit: Schichtleiter holen — nicht diskutieren."},{"t":"p","text":"04SichernFreundlich abschließen, Vorfall dem Schichtleiter melden, damit sich der Fehler nicht wiederholt."},{"t":"box","label":"","text":"Grenze"},{"t":"p","text":"Bei Beleidigung oder Aggression bleibst du ruhig und holst sofort den Schichtleiter. Niemand muss sich Beschimpfungen aussetzen — die Deeskalation übernimmt die Schichtleitung."}]},{"index":"5.7","eyebrow":"Teamkommunikation","heading":"Wir arbeiten füreinander","blocks":[{"t":"p","text":"Guter Service nach außen beginnt mit gutem Umgang nach innen. Wir arbeiten füreinander, nicht gegeneinander."},{"t":"table","rows":[["Probleme ansprechen","Direkt und respektvoll — nicht hinter dem Rücken"],["Fehler melden","Sofort und ehrlich, ohne Ausreden"],["Vor Gästen","Keine Diskussionen, keine Kritik — das klären wir intern"],["Respekt gilt","Gegenüber Kollegen, Chefs, Lieferanten und Gästen"]]}]},{"index":"5.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Ein Gast reklamiert, sein Burger sei falsch zusammengestellt."},{"t":"ul","items":["„Das war bestimmt so bestellt.\"","Diskussion vor anderen Gästen","Gast fühlt sich beschuldigt","Gast geht verärgert und kommt nie wieder"]},{"t":"ul","items":["„Das tut mir leid, ich mache das sofort neu.\"","Frischer Burger ohne Diskussion","Gast fühlt sich ernst genommen","Gast geht zufrieden und kommt wieder"]}]},{"index":"5.9","eyebrow":"Checkliste","heading":"Service-Check — jede Begegnung","blocks":[{"t":"ul","items":["Gast mit Blickkontakt & Lächeln begrüßt","Aufmerksam zugehört, Bestellung bestätigt","Bestellung vollständig & sauber übergeben","Mich bedankt und freundlich verabschiedet","Bei Problemen gelöst statt diskutiert","Ruhig geblieben, auch bei schwierigen Gästen","Keine Diskussion oder Kritik vor Gästen"]}]},{"index":"5.10","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Begrüßung & Verabschiedung","Schichtleiter","Stichprobe im Betrieb"],["Ton & Freundlichkeit","Schichtleiter","Laufend"],["Umgang mit Beschwerden","Schichtleiter","Bei jedem Vorfall"],["Reklamationen dokumentiert","Schichtleiter","Nach Vorfall Reklamationsblatt ergänzen"]]}]},{"index":"5.11","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Recht haben bringt nichts, wenn der Gast verärgert geht. Lösen statt diskutieren."},{"t":"p","text":"Wer wartend übersehen wird, fühlt sich unwichtig. Kurz Blickkontakt und „gleich für Sie da\"."},{"t":"p","text":"Private Sorgen bleiben hinter der Theke. Der Gast kann nichts dafür."},{"t":"p","text":"Interne Themen nie vor Gästen. Ruhig, intern, später klären."},{"t":"p","text":"Der letzte Eindruck bleibt. Jeden Gast freundlich verabschieden."},{"t":"p","text":"„War nicht mein Fehler\" hilft dem Gast nicht. Kurz entschuldigen und lösen."}]},{"index":"5.12","eyebrow":"Tipp vom Management","heading":"Best Practice — die extra Sekunde","blocks":[{"t":"box","label":"","text":"Ein Lächeln mehr"},{"t":"p","text":"Nimm dir bei jedem Gast eine Sekunde mehr: echter Blickkontakt, ein ehrliches „Lassen Sie es sich schmecken\". Diese eine Sekunde kostet nichts und ist oft der Unterschied zwischen „war okay\" und „da gehe ich wieder hin\". Menschen vergessen das Essen, aber nicht das Gefühl."}]},{"index":"5.13","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Der Gast steht im Mittelpunkt — Probleme werden gelöst, nicht diskutiert.","Servicebogen: begrüßen, aufnehmen, ausgeben, verabschieden.","Wir sprechen freundlich, respektvoll, direkt, professionell.","Beschwerde: zuhören, entschuldigen, lösen, sichern — ruhig bleiben.","Im Team: Probleme direkt ansprechen, nie vor Gästen streiten."]},{"t":"p","text":"QR-Code zu Service-Scripts & Reklamationsblatt. Link später ergänzen"}]}]},{"no":"06","title":"Stationen & Arbeitsabläufe","thesis":"Wir arbeiten nach SOP — nicht nach Gefühl, nicht nach Erinnerung, nicht nach eigener Meinung. Sondern nach Standard.","readtime":"ca. 15 Minuten","sections":[{"index":"6.1","eyebrow":"Einführung","heading":"Jede Station hat ihren Standard","blocks":[{"t":"lead","text":"Jeder arbeitet nach SOP. Nicht nach Gefühl. Nicht nach Erinnerung. Nicht nach eigener Meinung. Sondern nach Standard."},{"t":"p","text":"Unsere Küche ist in klare Stationen aufgeteilt. An jeder Station hängt eine laminierte SOP-Karte, die genau festlegt, wie dort gearbeitet wird. So entsteht dasselbe Ergebnis — egal wer arbeitet und an welchem Standort."},{"t":"box","label":"","text":"Was in dieses Kapitel gehört — und was nicht"},{"t":"p","text":"Dieses Kapitel erklärt das System: wie Stationen und SOP-Karten funktionieren. Die genauen Rezepte und Build-Schritte stehen auf den SOP-/Build-Karten und im vertraulichen Chef-Ordner — nie in diesem Handbuch."}]},{"index":"6.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Eine SOP-Karte lesen und ihren Aufbau verstehen.","Die Stationen und ihre Aufgabe kennen.","Mise en Place vor der Stoßzeit beherrschen.","Eine Station sauber wechseln und übergeben."]}]},{"index":"6.3","eyebrow":"Warum das wichtig ist","heading":"Gleiches Ergebnis, jedes Mal","blocks":[{"t":"p","text":"Wenn jeder nach eigenem Gefühl arbeitet, schmeckt jeder Burger anders. Der Gast will aber immer dasselbe Produkt — genau so gut wie beim letzten Mal. Die SOP-Karte macht das möglich: Sie hält den einen richtigen Weg fest, damit niemand improvisieren muss."},{"t":"p","text":"Für die Skalierung ist das entscheidend. Nur weil jede Station dokumentiert ist, kann ein neuer Standort dieselbe Qualität liefern — ohne dass der Inhaber daneben steht."}]},{"index":"6.4","eyebrow":"Das SOP-Karten-System","heading":"So liest du eine SOP-Karte","blocks":[{"t":"p","text":"Jede SOP-Karte ist gleich aufgebaut. Wer den Aufbau kennt, findet sich an jeder Station sofort zurecht."},{"t":"p","text":"Was am Ende herauskommt"},{"t":"p","text":"Wer die Station führt"},{"t":"p","text":"Geräte & Hilfsmittel"},{"t":"p","text":"Mise en Place"},{"t":"p","text":"Schritt für Schritt"},{"t":"p","text":"Wie „richtig\" aussieht"},{"t":"p","text":"Was oft schiefgeht"},{"t":"p","text":"Was geprüft wird"},{"t":"p","text":"Station sauber hinterlassen"},{"t":"p","text":"Zum Abhaken"},{"t":"p","text":"Richtwert pro Durchgang"},{"t":"box","label":"","text":"Regel"},{"t":"p","text":"Die SOP-Karte ist verbindlich. Änderungen am Produkt oder Ablauf trifft niemand eigenmächtig — nur die Geschäftsführung. Keine eigenmächtigen Rezept- oder Ablaufänderungen."}]},{"index":"6.5","eyebrow":"Die Stationen im Detail","heading":"Wo was passiert","blocks":[{"t":"p","text":"Jede Station hat eine klare Aufgabe und ihre eigene, laminierte SOP-Karte an der Station. Sie ist der verbindliche Standard — die folgenden Verweise zeigen, welche Karte(n) zu welcher Station gehören."},{"t":"p","text":"Zutaten, Soßen & Komponenten für den Tag vorbereiten."},{"t":"p","text":"Smashburger nach Build-Karte: Classic Smash & Chilli Milli."},{"t":"p","text":"Chicken & frittierte Produkte nach SOP zubereiten."},{"t":"p","text":"Pommes & Loaded Fries nach Standard."},{"t":"p","text":"Warme Soßen ansetzen & warmhalten."},{"t":"p","text":"Bestellung packen, Gast bedienen, kassieren."}]},{"index":"6.6","eyebrow":"Mise en Place","heading":"Alles an seinem Platz — vor der Stoßzeit","blocks":[{"t":"p","text":"„Mise en Place\" heißt: Vor dem Ansturm ist alles vorbereitet und griffbereit. Wer erst in der Stoßzeit sucht, verliert Zeit und Qualität."},{"t":"p","text":"01Station nach SOP aufbauenWerkzeuge & Ware genau dort, wo die SOP-Karte es vorgibt."},{"t":"p","text":"02Nach MIN/MAX auffüllenPuffer für schnelldrehende Ware anlegen (siehe Kapitel 08)."},{"t":"p","text":"03Temperaturen & Geräte prüfenGrill, Fritteuse, Bain-Marie einsatzbereit (siehe Kapitel 03 & 04)."},{"t":"p","text":"04Laufend nachfüllenWährend der Schicht auffüllen, bevor etwas ausgeht — nicht erst danach."}]},{"index":"6.7","eyebrow":"Stationswechsel & Rotation","heading":"Sauber übergeben, flexibel bleiben","blocks":[{"t":"p","text":"Wer eine Station verlässt oder wechselt, übergibt sie einsatzbereit — genau so, wie er sie selbst gerne vorfinden würde."},{"t":"table","rows":[["Beim Wechsel übergeben","Warum"],["Warenstand & Nachschub","Damit die Station weiterläuft ohne Engpass"],["Sauberkeit & Ordnung","Damit der Nächste sofort starten kann"],["Besonderheiten","Gerätethema, offene Bestellung, laufender Timer"]]},{"t":"box","label":"","text":"Cross-Training"},{"t":"p","text":"Jeder lernt mit der Zeit mehrere Stationen. Das macht das Team flexibel und dich wertvoller — ein wichtiger Schritt Richtung Schichtleiter."}]},{"index":"6.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Ein neuer Mitarbeiter steht das erste Mal am Grill."},{"t":"ul","items":["Menge & Reihenfolge „aus dem Bauch\"","Jeder Burger sieht anders aus","Keine Vorbereitung, sucht in der Stoßzeit","Ergebnis: unzuverlässig"]},{"t":"ul","items":["Folgt der Build-Karte Schritt für Schritt","Jeder Burger sieht gleich aus","Station vorbereitet, alles griffbereit","Ergebnis: konstant wie auf dem Bild"]}]},{"index":"6.9","eyebrow":"Checkliste","heading":"Station bereit & nach SOP","blocks":[{"t":"ul","items":["SOP-/Build-Karte gelesen und griffbereit","Station nach Karte aufgebaut","Ware nach MIN/MAX aufgefüllt","Geräte & Temperaturen einsatzbereit","Ablauf Schritt für Schritt nach SOP","Qualität geprüft — sieht aus wie im Standard","Station sauber & übergabebereit"]}]},{"index":"6.10","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Station nach SOP aufgebaut","Schichtleiter","Vor Betrieb"],["Produkt entspricht Standard","Mitarbeiter & Schichtleiter","Laufend"],["Keine Ablaufänderung","Schichtleiter","Stichprobe"],["Saubere Übergabe","Schichtleiter","Bei Wechsel"]]}]},{"index":"6.11","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Auch Erfahrene folgen der Karte. Routine ist kein Grund für Abweichung."},{"t":"p","text":"Rezept- oder Ablaufänderungen trifft nur die Geschäftsführung — nie die Station."},{"t":"p","text":"Wer in der Stoßzeit sucht, verliert Tempo und Qualität. Vorher vorbereiten."},{"t":"p","text":"Leer, dreckig, ohne Info — der Nächste startet im Rückstand. Sauber übergeben."}]},{"index":"6.12","eyebrow":"Tipp vom Management","heading":"Best Practice — die Karte ist dein Freund","blocks":[{"t":"box","label":"","text":"Nicht raten — nachschauen"},{"t":"p","text":"Niemand muss alles auswendig können. Die SOP-Karte hängt genau deshalb an der Station: damit du im Zweifel nachschaust statt rätst. Ein kurzer Blick auf die Karte ist nie ein Zeichen von Schwäche — sondern von Professionalität. Wer nach Standard arbeitet, macht die wenigsten Fehler."}]},{"index":"6.13","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Wir arbeiten nach SOP — nicht nach Gefühl oder Erinnerung.","Jede SOP-Karte ist gleich aufgebaut — vom Ziel bis zur Reinigung.","Rezepte stehen im Chef-Ordner, nicht im Handbuch.","Mise en Place vor der Stoßzeit — alles an seinem Platz.","Keine eigenmächtigen Änderungen, saubere Übergabe."]},{"t":"p","text":"QR-Code zur digitalen Übersicht aller SOP- & Build-Karten. Link später ergänzen"}]}]},{"no":"07","title":"Qualitätskontrolle & Standards","thesis":"Jeder Burger soll aussehen wie auf dem Werbebild. Keine Ausnahme. Lieber wenige Produkte perfekt als viele durchschnittlich.","readtime":"ca. 12 Minuten","sections":[{"index":"7.1","eyebrow":"Einführung","heading":"Kein Produkt geht ungeprüft raus","blocks":[{"t":"lead","text":"Jedes Produkt wird vor der Ausgabe geprüft: Optik, Temperatur, Sauberkeit, Vollständigkeit, Verpackung."},{"t":"p","text":"Qualitätskontrolle ist kein zusätzlicher Schritt am Ende — sie ist der letzte, kurze Blick, bevor der Gast sein Essen bekommt. Dieser Blick entscheidet, ob wir unser Versprechen halten: dieselbe Qualität, jedes Mal."},{"t":"box","label":"","text":"Unser Qualitätsversprechen"},{"t":"p","text":"Was den Standard nicht erfüllt, wird nicht ausgegeben. Im Zweifel neu machen."}]},{"index":"7.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Jedes Produkt nach den 5 Kriterien prüfen.","Erkennen, ob etwas dem Standard entspricht — „wie auf dem Bild\".","Richtig handeln bei Abweichung.","Verstehen, warum Konstanz wichtiger ist als Tempo."]}]},{"index":"7.3","eyebrow":"Warum das wichtig ist","heading":"Konstanz schafft Vertrauen","blocks":[{"t":"p","text":"Ein Gast, der einmal ein perfektes Produkt bekommt, erwartet es beim nächsten Mal genauso. Wird es schlechter, ist das Vertrauen weg — oft für immer. Genau deshalb gilt: lieber wenige Produkte perfekt als viele durchschnittlich."},{"t":"p","text":"Als wachsende Marke ist Konstanz unser wichtigstes Versprechen. Jeder geprüfte Burger hält es, jeder ungeprüfte setzt es aufs Spiel."}]},{"index":"7.4","eyebrow":"Die 5 Prüfkriterien","heading":"Worauf wir bei jedem Produkt achten","blocks":[{"t":"p","text":"Prüfe: Sieht es aus wie im Standard? Sauber angerichtet, richtige Menge, appetitlich — wie auf dem Bild."},{"t":"p","text":"Prüfe: Heiß, was heiß sein muss. Kalt, was kalt sein muss. Nichts lauwarm."},{"t":"p","text":"Prüfe: Keine Fettränder, keine Krümel, saubere Ränder — innen wie außen."},{"t":"p","text":"Prüfe: Ist alles dabei? Bestellung komplett, Beilagen, Soßen, Servietten."},{"t":"p","text":"Prüfe: Richtig & sauber verpackt, nichts läuft aus, Marke ordentlich sichtbar."}]},{"index":"7.5","eyebrow":"Der Qualitäts-Check","heading":"Der 5-Sekunden-Blick vor der Ausgabe","blocks":[{"t":"p","text":"Vor jeder Ausgabe ein kurzer, fester Ablauf — er kostet Sekunden und rettet den Eindruck."},{"t":"p","text":"01AnsehenOptik & Sauberkeit prüfen — sieht es aus wie im Standard?"},{"t":"p","text":"02FühlenTemperatur stimmt — heiß bzw. kalt wie vorgesehen."},{"t":"p","text":"03AbgleichenVollständigkeit mit der Bestellung — nichts fehlt."},{"t":"p","text":"04Verpacken & ausgebenSauber verpacken, freundlich übergeben (siehe Kapitel 05)."}]},{"index":"7.6","eyebrow":"Bei Abweichung","heading":"Entspricht es dem Standard?","blocks":[{"t":"p","text":"Die Frage ist immer dieselbe — und die Antwort entscheidet, ob das Produkt rausgeht."},{"t":"p","text":"Sauber verpacken und freundlich an den Gast übergeben."},{"t":"p","text":"Produkt zurückhalten, neu zubereiten. Ursache dem Schichtleiter melden, damit sich der Fehler nicht wiederholt."},{"t":"box","label":"","text":"Grundsatz"},{"t":"p","text":"Ein zweifelhaftes Produkt geht nie „mal durch\". Im Zweifel immer neu machen — die paar Cent sind billiger als ein verlorener Gast."}]},{"index":"7.7","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Stoßzeit, der Burger ist etwas schief zusammengefallen."},{"t":"ul","items":["Burger schief, Soße läuft heraus","Wird trotzdem ausgegeben","Gast sieht: unordentlich","Erwartung vom Bild nicht erfüllt"]},{"t":"ul","items":["Kurz geprüft, Abweichung erkannt","Sauber neu angerichtet","Gast sieht: wie auf dem Bild","Erwartung erfüllt — Gast kommt wieder"]}]},{"index":"7.8","eyebrow":"Checkliste","heading":"Qualitäts-Check — vor jeder Ausgabe","blocks":[{"t":"ul","items":["Optik: sieht aus wie im Standard","Temperatur: heiß bzw. kalt wie vorgesehen","Sauberkeit: keine Ränder, keine Krümel","Vollständigkeit: Bestellung komplett","Verpackung: sauber & dicht verpackt","Bei Abweichung: neu gemacht & gemeldet"]}]},{"index":"7.9","eyebrow":"Qualitätskontrolle","heading":"Wer prüft die Qualität","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["5-Kriterien-Check","Ausgebender Mitarbeiter","Vor jeder Ausgabe"],["Stichprobe Produktqualität","Schichtleiter","Laufend im Betrieb"],["Abweichungen dokumentiert","Schichtleiter","Bei jedem Vorfall Formular ergänzen"],["Standard-Abgleich (Bild)","Schichtleiter","Regelmäßig Referenzbilder ergänzen"]]}]},{"index":"7.10","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Gerade dann zählt Konstanz. Der Check kostet nur Sekunden."},{"t":"p","text":"Ein schlechtes Produkt kostet mehr als ein neues. Im Zweifel neu machen."},{"t":"p","text":"Fehlende Soße oder Beilage ärgert jeden Gast. Immer abgleichen."},{"t":"p","text":"Auslaufende Verpackung ruiniert den Eindruck. Sauber & dicht verpacken."}]},{"index":"7.11","eyebrow":"Tipp vom Management","heading":"Best Practice — würdest du es selbst essen?","blocks":[{"t":"box","label":"","text":"Der ehrliche Test"},{"t":"p","text":"Bevor ein Produkt rausgeht, stell dir eine Frage: Würde ich das selbst so essen wollen — oder es einem Freund servieren? Wenn die Antwort „nein\" ist, geht es zurück. Dieser ehrliche Blick ist der beste Qualitätsprüfer, den wir haben."}]},{"index":"7.12","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Jedes Produkt vor der Ausgabe nach 5 Kriterien prüfen.","Optik, Temperatur, Sauberkeit, Vollständigkeit, Verpackung.","Es muss aussehen wie auf dem Bild — keine Ausnahme.","Bei Abweichung: nicht ausgeben, neu machen, melden.","Lieber wenige Produkte perfekt als viele durchschnittlich."]},{"t":"p","text":"QR-Code zu Referenzfotos „So sieht es richtig aus\". Link später ergänzen"}]}]},{"no":"08","title":"Bestellung, Lieferanten & Inventur","thesis":"Zu viel bestellen bedeutet Verschwendung. Zu wenig bedeutet „ausverkauft\". Das MIN/MAX-System hält die Balance.","readtime":"ca. 18 Minuten","sections":[{"index":"8.1","eyebrow":"Einführung","heading":"Nie zu viel, nie zu wenig","blocks":[{"t":"lead","text":"Gute Bestellung heißt: immer genug Ware, um jeden Gast zu bedienen — und so wenig Verschwendung wie möglich."},{"t":"p","text":"Zwei Fehler kosten uns Geld: zu viel bestellen (Ware verdirbt) oder zu wenig (Produkte sind ausverkauft, Gäste gehen enttäuscht). Unser MIN/MAX-System und der feste Bestellkalender sorgen dafür, dass beides selten passiert."},{"t":"box","label":"","text":"Wer bestellt"},{"t":"p","text":"Bestellungen laufen über die Schichtleitung bzw. eingewiesene Mitarbeiter — nach System, nicht nach Bauchgefühl. Bestellfristen sind verbindlich."}]},{"index":"8.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Das MIN/MAX-System verstehen und anwenden.","Alle vier Lieferanten mit Rhythmus & Fristen kennen.","Nach dem Bestellkalender rechtzeitig bestellen.","Wareneingang prüfen und richtig lagern.","Eine Inventur durchführen."]}]},{"index":"8.3","eyebrow":"Das MIN/MAX-System","heading":"Puffer statt Rätselraten","blocks":[{"t":"p","text":"Jeder Artikel hat einen MIN-Wert (Mindestbestand — jetzt nachbestellen) und einen MAX-Wert (bis hierhin auffüllen). Wie wir damit umgehen, hängt vom Artikel ab."},{"t":"p","text":"Ware, die täglich stark verbraucht wird."},{"t":"p","text":"Regel: Immer einen Puffer halten. Sobald der Bestand den MIN-Wert erreicht, bis MAX nachbestellen. Nie ausverkauft."},{"t":"p","text":"Perishables, die selten gebraucht werden & schnell verderben."},{"t":"p","text":"Regel: Erst nachbestellen, wenn fast leer. So vermeiden wir Verderb und Verschwendung."}]},{"index":"8.4","eyebrow":"Unsere Lieferanten","heading":"Vier Quellen, vier Rhythmen","blocks":[]},{"index":"8.5","eyebrow":"Der Bestellkalender","heading":"Wann was bestellt wird","blocks":[{"t":"p","text":"Farbcodiert nach Lieferant. So sieht jeder auf einen Blick, was heute ansteht."},{"t":"box","label":"","text":"Offene Punkte"},{"t":"p","text":"Winters-Lieferung am Montag: Der Vorabend fällt auf Sonntag (geschlossen) — Bestellzeitpunkt festlegen. später ergänzenKM Frischdienst: alle 1–2 Wochen nach MIN-Bestand, Abholtermin fix einplanen. Tag später ergänzen"}]},{"index":"8.6","eyebrow":"Bestellablauf","heading":"In vier Schritten bestellen","blocks":[{"t":"p","text":"01Bestand gegen MIN/MAX prüfenAlle Artikel des jeweiligen Lieferanten durchgehen. Was ist am oder unter MIN?"},{"t":"p","text":"02Bedarf notierenMengen bis MAX bestimmen. Schnelldreher immer auffüllen, Langsamdreher nur bei Bedarf."},{"t":"p","text":"03Fristgerecht bestellenNach Bestellkalender: Winters am Vorabend, C&C Di Abend + Anruf Mi vor 12:00."},{"t":"p","text":"04Bestätigen & dokumentierenBestellung festhalten, damit die nächste Schicht sie beim Wareneingang abgleichen kann."}]},{"index":"8.7","eyebrow":"Wareneingang & Lagerung","heading":"Prüfen, kühlen, einräumen","blocks":[{"t":"table","rows":[["Schritt","Was zu tun ist"],["Menge prüfen","Lieferung mit Bestellung abgleichen — stimmt alles?"],["Qualität prüfen","Frische, Verpackung, Temperatur der Kühlware kontrollieren"],["Sofort kühlen","Kühl- & TK-Ware zuerst wegräumen, Kühlkette halten (Kapitel 03)"],["FIFO einräumen","Neue Ware nach hinten, ältere nach vorne, mit Datum"],["Abweichung melden","Fehlmengen oder Mängel sofort dem Schichtleiter melden"]]}]},{"index":"8.8","eyebrow":"Inventur","heading":"Wissen, was wir haben","blocks":[{"t":"p","text":"Eine regelmäßige Inventur zeigt den echten Bestand, deckt Verluste auf und macht die Bestellung genauer."},{"t":"table","rows":[["Wann","Regelmäßig, z. B. wöchentlich Rhythmus festlegen"],["Wie","Bestand je Artikel zählen und mit MIN/MAX abgleichen"],["Wer","Schichtleiter, ggf. mit einem Mitarbeiter"],["Ergebnis","Fehlbestände, Verderb & Verbrauch dokumentieren"]]}]},{"index":"8.9","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Freitagabend, das Wochenende steht bevor."},{"t":"ul","items":["Niemand prüft den Bestand","Pommes gehen Samstagmittag aus","Gäste gehen enttäuscht","Gleichzeitig verdirbt zu viel Salat"]},{"t":"ul","items":["Bestand gegen MIN geprüft","Schnelldreher fristgerecht bestellt","Samstag durchgehend lieferfähig","Frische nur nach Bedarf — kein Verderb"]}]},{"index":"8.10","eyebrow":"Checkliste","heading":"Bestell-Check","blocks":[{"t":"ul","items":["Bestand gegen MIN/MAX geprüft","Schnelldreher bis MAX aufgefüllt","Frische/Langsamdreher nur bei Bedarf","Bestellkalender beachtet — Frist eingehalten","C&C: Di bestellt & Mi vor 12:00 angerufen","Bestellung dokumentiert für den Wareneingang","Wareneingang geprüft & nach FIFO eingeräumt"]}]},{"index":"8.11","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Bestellfristen eingehalten","Schichtleiter","Nach Bestellkalender"],["Wareneingang abgeglichen","Schichtleiter","Bei jeder Lieferung"],["FIFO & Kühlung korrekt","Mitarbeiter & Schichtleiter","Beim Einräumen"],["Inventur durchgeführt","Schichtleiter","Nach festgelegtem Rhythmus"]]}]},{"index":"8.12","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Wer den Vorabend oder den Mi-Anruf verpasst, hat keine Lieferung. Kalender ernst nehmen."},{"t":"p","text":"Salat & Co. auf Verdacht kaufen führt zu Verderb. Nur nach Bedarf bestellen."},{"t":"p","text":"Ausverkaufte Pommes am Wochenende ärgern jeden Gast. Puffer halten."},{"t":"p","text":"Fehlmengen fallen sonst erst in der Stoßzeit auf. Sofort abgleichen."}]},{"index":"8.13","eyebrow":"Tipp vom Management","heading":"Best Practice — der feste Bestell-Slot","blocks":[{"t":"box","label":"","text":"Immer zur selben Zeit"},{"t":"p","text":"Mach die Bestellung jeden Abend zur festen Uhrzeit — zum Beispiel beim Schließen. Ein fester Slot wird nie vergessen. Und wer beim Auffüllen schon notiert, was zur Neige geht, hat die halbe Bestellung fertig, bevor er überhaupt zählt. Routine schlägt Erinnerung."}]},{"index":"8.14","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["MIN/MAX: Schnelldreher mit Puffer, Frische nur bei Bedarf.","Vier Lieferanten: ALDI täglich, Winters Mo/Mi/Do/Fr, C&C wöchentlich, KM alle 1–2 Wochen.","Fristen zählen: Winters am Vorabend, C&C Di + Anruf Mi vor 12:00.","Wareneingang prüfen, kühlen, FIFO einräumen.","Regelmäßige Inventur macht Bestellung genau."]},{"t":"p","text":"QR-Code zum digitalen Bestellkalender & zur MIN/MAX-Liste. Link später ergänzen"}]}]},{"no":"09","title":"Arbeitszeiten, Pausen & Krankmeldung","thesis":"Ein Team ist nur so verlässlich wie seine Zeiten. Pünktlich heißt einsatzbereit — und wer ausfällt, meldet sich rechtzeitig.","readtime":"ca. 12 Minuten","sections":[{"index":"9.1","eyebrow":"Einführung","heading":"Zeiten sind Teamsache","blocks":[{"t":"lead","text":"Wenn einer zu spät kommt, wartet nicht nur der Chef — das ganze Team muss den Anfang alleine stemmen."},{"t":"p","text":"Feste Arbeitszeiten, geregelte Pausen und eine rechtzeitige Krankmeldung sorgen dafür, dass jede Schicht planbar läuft. Verlässlichkeit ist einer unserer Kernwerte — und sie zeigt sich zuerst an der Uhr."}]},{"index":"9.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel weißt","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Die Öffnungszeiten & Schichten kennen.","Was pünktlich bei uns bedeutet.","Wie Pausen geregelt sind.","Wie du dich richtig krankmeldest.","Wie geplante Abwesenheit angefragt wird."]}]},{"index":"9.3","eyebrow":"Öffnungszeiten & Schichten","heading":"Unser Tag im Überblick","blocks":[{"t":"p","text":"Geöffnet Montag bis Samstag, 10:30–20:00 Uhr. Die Vorbereitung beginnt vorher, das Schließen dauert etwas länger."},{"t":"table","rows":[["Zeitfenster","Uhrzeit","Fokus"],["Prep","ab 09:30","Vorbereiten, Öffnungsablauf (Kapitel 04)"],["Schicht 1","11:30–19:30","Mittags- & Nachmittagsgeschäft"],["Schicht 2","16:30–20:30","Abendgeschäft & Schließablauf"]]}]},{"index":"9.4","eyebrow":"Pünktlichkeit","heading":"10 Minuten vorher — einsatzbereit","blocks":[{"t":"p","text":"Bei MeatyMunch heißt pünktlich nicht „ankommen\", sondern startklar sein. Zum Schichtbeginn stehst du fertig an der Station."},{"t":"box","label":"","text":"Vor Schichtbeginn"},{"t":"ul","items":["10 Minuten vorher vor Ort","Umgezogen & Erscheinungsbild geprüft (Kapitel 01)","Hände gewaschen","Station bereit — startklar gemeldet"]}]},{"index":"9.5","eyebrow":"Pausen","heading":"Erholen — aber geregelt","blocks":[{"t":"p","text":"Pausen sind wichtig, damit du frisch bleibst. Sie werden mit der Schichtleitung abgestimmt, damit die Station immer besetzt ist."},{"t":"box","label":"","text":"Gesetzlicher Rahmen (Arbeitszeitgesetz)"},{"t":"p","text":"Bei mehr als 6 Stunden Arbeit: mindestens 30 Minuten Pause. Bei mehr als 9 Stunden: mindestens 45 Minuten. Länger als 6 Stunden ohne Pause ist nicht erlaubt."},{"t":"table","rows":[["Wann","Mit der Schichtleitung abgestimmt, nicht in der Stoßzeit feste Pausenzeiten ergänzen"],["Wo","Im festgelegten Pausenbereich Ort ergänzen"],["Handy","Private Nutzung nur in der Pause (Kapitel 01)"]]}]},{"index":"9.6","eyebrow":"Krankmeldung","heading":"Krank? Sofort Bescheid geben","blocks":[{"t":"p","text":"Wer krank ist, kann nichts dafür — aber jeder kann sich rechtzeitig melden. Je früher, desto besser kann die Schicht umgeplant werden."},{"t":"p","text":"01Sofort meldenSo früh wie möglich, unbedingt vor Schichtbeginn — nicht erst kurz davor."},{"t":"p","text":"02Richtige Person informierenSchichtleitung bzw. Chef direkt kontaktieren. Ansprechpartner & Weg ergänzen"},{"t":"p","text":"03Dauer angebenKurz sagen, ob und wie lange du voraussichtlich ausfällst."},{"t":"p","text":"04AU nachreichenÄrztliche Bescheinigung (AU) nach Vorgabe einreichen. Frist & Regelung ergänzen"},{"t":"box","label":"","text":"Wichtig"},{"t":"p","text":"Einfach nicht erscheinen geht gar nicht. Eine fehlende Krankmeldung ist ein schwerer Verstoß (siehe Kapitel 11). Lieber einmal zu früh melden als zu spät."}]},{"index":"9.7","eyebrow":"Geplante Abwesenheit","heading":"Urlaub & Schichttausch","blocks":[{"t":"p","text":"Geplante Abwesenheit wird frühzeitig angefragt, damit die Schicht rechtzeitig besetzt werden kann."},{"t":"table","rows":[["Urlaub","Rechtzeitig bei der Schichtleitung/Chef beantragen Vorlauf & Weg ergänzen"],["Schichttausch","Nur nach Absprache & Bestätigung durch die Schichtleitung"],["Verspätung absehbar","Sofort informieren, nicht kommentarlos zu spät kommen"]]}]},{"index":"9.8","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Ein Mitarbeiter wacht morgens krank auf."},{"t":"ul","items":["Meldet sich gar nicht","Team steht plötzlich unterbesetzt da","Schichtleiter erfährt es erst beim Ausbleiben","Stress & Vertrauensverlust"]},{"t":"ul","items":["Meldet sich früh, vor Schichtbeginn","Nennt voraussichtliche Dauer","Schichtleiter plant rechtzeitig um","Schicht läuft trotzdem rund"]}]},{"index":"9.9","eyebrow":"Checkliste","heading":"Meine Zeiten im Griff","blocks":[{"t":"ul","items":["Ich kenne meine Schichtzeiten","Ich bin 10 Minuten vorher einsatzbereit","Pausen mit der Schichtleitung abgestimmt","Bei Krankheit melde ich mich sofort, vor Schichtbeginn","AU nach Vorgabe nachgereicht","Urlaub/Tausch rechtzeitig angefragt & bestätigt"]}]},{"index":"9.10","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Pünktlich & einsatzbereit","Schichtleiter","Bei Schichtbeginn"],["Pausen dokumentiert","Schichtleiter","Laufend Zeiterfassung ergänzen"],["Krankmeldung erfasst","Schichtleiter","Am Krankheitstag"],["AU eingegangen","Schichtleiter / Personalakte","Nach Frist"]]}]},{"index":"9.11","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Dann erst umziehen heißt: zu spät. 10 Minuten vorher einsatzbereit."},{"t":"p","text":"„Kurz vor Schicht\" lässt keine Umplanung zu. So früh wie möglich melden."},{"t":"p","text":"Pause dann, wenn die Station es zulässt — abgestimmt mit dem Schichtleiter."},{"t":"p","text":"Tausch gilt erst nach Bestätigung. Sonst fehlt am Ende jemand."}]},{"index":"9.12","eyebrow":"Tipp vom Management","heading":"Best Practice — Puffer einplanen","blocks":[{"t":"box","label":"","text":"Lieber 15 als 10"},{"t":"p","text":"Plane deinen Weg so, dass du auch bei Stau oder verpasstem Bus pünktlich bist. Wer regelmäßig ein paar Minuten früher da ist, wirkt zuverlässig — und Zuverlässigkeit ist genau das, was bei uns zu mehr Verantwortung führt. Pünktlichkeit ist die einfachste Art, Vertrauen aufzubauen."}]},{"index":"9.13","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Öffnung Mo–Sa 10:30–20:00, Prep ab 09:30, zwei Schichten.","Pünktlich = 10 Minuten vorher, einsatzbereit.","Pausen mit der Schichtleitung abgestimmt, gesetzlicher Rahmen gilt.","Krank? Sofort und vor Schichtbeginn melden, AU nachreichen.","Urlaub & Tausch nur rechtzeitig & bestätigt."]},{"t":"p","text":"QR-Code zum aktuellen Schichtplan & Krankmelde-Kontakt. Link später ergänzen"}]}]},{"no":"10","title":"Notfälle & Arbeitsschutz","thesis":"Eine Küche ist voller Hitze, Öl und Messer. Sicherheit geht vor Tempo — immer. Kein Produkt ist eine Verletzung wert.","readtime":"ca. 14 Minuten","sections":[{"index":"10.1","eyebrow":"Einführung","heading":"Sicherheit geht immer vor","blocks":[{"t":"lead","text":"Kein Burger, keine Bestellung und keine Stoßzeit ist eine Verletzung wert. Im Zweifel gilt immer: erst Sicherheit, dann Tempo."},{"t":"p","text":"In unserer Küche arbeiten wir mit heißem Öl, offenen Flammen, scharfen Messern und nassen Böden. Die meisten Unfälle sind vermeidbar — wenn jeder die Gefahren kennt und ruhig richtig reagiert. Dieses Kapitel zeigt, wie."}]},{"index":"10.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel kannst","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Die Notrufnummern und internen Kontakte kennen.","Die häufigsten Gefahren vermeiden.","Bei Verletzungen ruhig Erste Hilfe leisten.","Richtig auf Feuer & Fettbrand reagieren.","Wissen, wie Evakuierung und Unfallmeldung laufen."]}]},{"index":"10.3","eyebrow":"Notrufnummern","heading":"Im Ernstfall: ruhig anrufen","blocks":[{"t":"box","label":"","text":"Beim Notruf sagen"},{"t":"p","text":"Wo ist es passiert · Was ist passiert · Wie viele Betroffene · Welche Verletzungen · Warten auf Rückfragen. Nicht zuerst auflegen."}]},{"index":"10.4","eyebrow":"Die häufigsten Gefahren","heading":"Kennen heißt vermeiden","blocks":[{"t":"p","text":"RisikoVerbrennungen durch Grill, Fritteuse, heißes Öl & Dampf."},{"t":"p","text":"SchutzAbstand halten, kein Wasser in heißes Öl, langsam & konzentriert arbeiten."},{"t":"p","text":"RisikoSchnittverletzungen durch scharfe Klingen."},{"t":"p","text":"SchutzScharfe Messer, Schneidbrett, weg von der Hand schneiden, nie nach fallendem Messer greifen."},{"t":"p","text":"RisikoStürze auf nassem oder fettigem Boden."},{"t":"p","text":"SchutzVerschüttetes sofort aufwischen, rutschfeste Schuhe, Warnschild bei nassem Boden."},{"t":"p","text":"RisikoStromschlag oder Defekt an Geräten."},{"t":"p","text":"SchutzKeine nassen Hände an Geräten/Steckern, Defekte melden, nicht selbst reparieren."}]},{"index":"10.5","eyebrow":"Erste Hilfe","heading":"Ruhig & richtig reagieren","blocks":[{"t":"p","text":"Bei jeder Verletzung gilt: Ruhe bewahren, Schichtleiter informieren, bei Bedarf 112 rufen. Der Erste-Hilfe-Kasten und ausgebildete Ersthelfer sind im Betrieb vorhanden."},{"t":"p","text":"Sofort von der Hitze weg. Betroffene Stelle einige Minuten unter kühlem (nicht eiskaltem) fließendem Wasser kühlen. Kein Eis direkt auf die Haut, Blasen nicht öffnen, locker abdecken. Bei größerer oder tiefer Verbrennung: 112."},{"t":"p","text":"Wunde säubern, mit sauberem Verband abdrücken, ruhig hochhalten. Bei tiefer oder stark blutender Wunde: Druck halten und 112 bzw. Arzt."},{"t":"box","label":"","text":"Wichtig"},{"t":"p","text":"Dies sind Grundregeln, kein Ersatz für einen Erste-Hilfe-Kurs. Im Zweifel immer 112 und den ausgebildeten Ersthelfer holen. Ersthelfer & Kasten-Standort ergänzen"}]},{"index":"10.6","eyebrow":"Feuer & Fettbrand","heading":"Der wichtigste Satz der Küche","blocks":[{"t":"box","label":"","text":"Lebensgefahr"},{"t":"p","text":"Niemals Wasser auf brennendes Fett oder Öl! Das führt zu einer schlagartigen Stichflamme. Fettbrand wird mit Löschdecke, Deckel oder einem Fettbrand-Feuerlöscher (Brandklasse F) erstickt — nie mit Wasser."},{"t":"p","text":"01Ruhe & Gerät ausWenn möglich Fritteuse/Grill/Strom ausschalten, ohne dich zu gefährden."},{"t":"p","text":"02Kleinbrand erstickenFettbrand: Deckel/Löschdecke. Sonst passenden Feuerlöscher nutzen. Löscher-Standort ergänzen"},{"t":"p","text":"03Gefahr? 112 & rausBreitet es sich aus: nicht riskieren — 112 rufen, Gäste & Team hinausbringen."},{"t":"p","text":"04Sammeln & meldenAm Sammelplatz sammeln, Vollzähligkeit prüfen, Chef informieren. Sammelplatz ergänzen"}]},{"index":"10.7","eyebrow":"Evakuierung","heading":"Raus — ruhig & vollständig","blocks":[{"t":"table","rows":[["Ruhe bewahren","Keine Panik verbreiten, klar & laut anweisen"],["Gäste zuerst","Gäste ruhig zum Ausgang leiten"],["Kürzester Weg","Nächsten Notausgang nutzen Fluchtweg/Notausgang ergänzen"],["Nichts holen","Keine Wertsachen holen — Menschen zählen"],["Sammelplatz","Am festgelegten Punkt sammeln & zählen Ort ergänzen"]]}]},{"index":"10.8","eyebrow":"Unfall melden","heading":"Jeder Unfall wird gemeldet","blocks":[{"t":"p","text":"Auch kleine Verletzungen werden immer dem Schichtleiter gemeldet und dokumentiert. So können Gefahren beseitigt werden, bevor Schlimmeres passiert."},{"t":"table","rows":[["Sofort","Verletzung versorgen & Schichtleiter informieren"],["Dokumentieren","Was, wann, wie passiert — im Unfallbericht Formular ergänzen"],["Ursache beseitigen","Gefahrenquelle sichern, damit es sich nicht wiederholt"]]}]},{"index":"10.9","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"In der Fritteuse fängt das Öl Feuer."},{"t":"ul","items":["Panik, Wasser auf das Fett","Stichflamme, Feuer breitet sich aus","Niemand ist informiert","Große Gefahr für alle"]},{"t":"ul","items":["Fritteuse aus, Deckel/Löschdecke drauf","Flamme erstickt, kein Wasser","Bei Ausbreitung: 112 & raus","Team & Gäste in Sicherheit"]}]},{"index":"10.10","eyebrow":"Checkliste","heading":"Sicherheits-Check","blocks":[{"t":"ul","items":["Ich kenne 112 & die internen Kontakte","Ich weiß, wo Feuerlöscher & Löschdecke sind","Ich weiß, wo der Erste-Hilfe-Kasten ist","Ich kenne Notausgang & Sammelplatz","Kein Wasser auf Fettbrand — Deckel/Decke","Verschüttetes sofort aufgewischt","Jeden Unfall gemeldet & dokumentiert"]}]},{"index":"10.11","eyebrow":"Qualitätskontrolle","heading":"Kontrollpunkte","blocks":[{"t":"table","rows":[["Kontrollpunkt","Wer","Wann"],["Feuerlöscher & Löschdecke einsatzbereit","Schichtleiter","Regelmäßig Prüfintervall ergänzen"],["Erste-Hilfe-Kasten gefüllt","Schichtleiter","Regelmäßig"],["Fluchtwege frei","Alle","Laufend"],["Unfälle dokumentiert","Schichtleiter","Bei jedem Vorfall"]]}]},{"index":"10.12","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler","blocks":[{"t":"p","text":"Der gefährlichste Fehler überhaupt. Immer Deckel, Löschdecke oder Klasse-F-Löscher."},{"t":"p","text":"Auch Kleines wird gemeldet — sonst bleibt die Gefahrenquelle bestehen."},{"t":"p","text":"Ein Sturz ist schnell passiert. Sofort aufwischen, Schild aufstellen."},{"t":"p","text":"Kartons vor dem Ausgang kosten im Ernstfall Sekunden. Wege immer frei halten."}]},{"index":"10.13","eyebrow":"Tipp vom Management","heading":"Best Practice — kenne deinen Container","blocks":[{"t":"box","label":"","text":"Am ersten Tag prüfen"},{"t":"p","text":"Schau dir an deinem ersten Tag genau an, wo Feuerlöscher, Löschdecke, Erste-Hilfe-Kasten und Notausgang sind. Im Ernstfall hast du keine Zeit zum Suchen. Wer die Wege kennt, bleibt ruhig — und Ruhe rettet."}]},{"index":"10.14","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Notruf 112 (Feuer/Rettung), 110 (Polizei) — plus intern melden.","Hauptgefahren: Hitze/Fett, Messer, Nässe, Strom.","Niemals Wasser auf Fettbrand — Deckel, Löschdecke, Klasse-F-Löscher.","Verletzung: ruhig Erste Hilfe, im Zweifel 112 & Ersthelfer.","Jeden Unfall melden & dokumentieren, Fluchtwege frei halten."]},{"t":"p","text":"QR-Code zum Notfallplan, Fluchtwegplan & Ersthelfer-Liste. Link später ergänzen"}]}]},{"no":"11","title":"Verhalten, Regeln & Konsequenzen","thesis":"Klare Regeln schützen alle. Fehler dürfen passieren — Fehlverhalten nicht. Und jeder wird gleich und fair behandelt.","readtime":"ca. 12 Minuten","sections":[{"index":"11.1","eyebrow":"Einführung","heading":"Regeln geben Sicherheit","blocks":[{"t":"lead","text":"Klare Regeln sind kein Misstrauen, sondern Fairness: Jeder weiß, was gilt — und jeder wird gleich behandelt."},{"t":"p","text":"Ein gutes Team funktioniert, weil sich alle auf dieselben Regeln verlassen können. Wer sich daran hält, muss nie Angst vor Willkür haben. Und wer einen ehrlichen Fehler macht, bekommt die Chance, daraus zu lernen. Dieses Kapitel erklärt, was gilt, was nicht — und was passiert, wenn Regeln gebrochen werden."}]},{"index":"11.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel weißt","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Den Unterschied zwischen Fehler und Fehlverhalten.","Was bei uns nicht akzeptiert wird.","Wie das 3-Stufen-Modell funktioniert.","Was zu einer sofortigen Trennung führen kann."]}]},{"index":"11.3","eyebrow":"Fehler vs. Fehlverhalten","heading":"Zwei völlig verschiedene Dinge","blocks":[{"t":"p","text":"Wir unterscheiden klar zwischen einem ehrlichen Fehler und bewusstem Fehlverhalten. Das eine ist Teil des Lernens, das andere nicht."},{"t":"p","text":"Etwas versehentlich falsch gemacht, sofort gemeldet, daraus gelernt. Fehler dürfen passieren — sie dürfen sich nur nicht wiederholen."},{"t":"p","text":"Absichtlicher Regelbruch, Vertuschen oder Wiederholung trotz Hinweis. Das wird nicht toleriert und hat Konsequenzen."},{"t":"box","label":"","text":"Unsere Lernkultur"},{"t":"p","text":"Fehler dürfen passieren. Fehler dürfen nicht wiederholt werden. Wer offen mit Fehlern umgeht, hilft dem ganzen Team, besser zu werden."}]},{"index":"11.4","eyebrow":"Was nicht akzeptiert wird","heading":"Klare Grenzen","blocks":[{"t":"p","text":"Folgendes Verhalten wird bei MeatyMunch nicht toleriert:"}]},{"index":"11.5","eyebrow":"Das 3-Stufen-Modell","heading":"Fair, transparent, nachvollziehbar","blocks":[{"t":"p","text":"Bei wiederholtem oder ernstem Fehlverhalten reagieren wir in klaren Stufen — nie willkürlich, immer nachvollziehbar."},{"t":"p","text":"Klärendes Gespräch: Was ist passiert, was muss sich ändern? Chance zur Korrektur."},{"t":"p","text":"Hält der Verstoß an, folgt eine schriftliche Verwarnung — dokumentiert in der Personalakte."},{"t":"p","text":"Ändert sich nichts, folgt die Beendigung des Arbeitsverhältnisses nach den geltenden Regeln."},{"t":"box","label":"","text":"Rechtlicher Rahmen"},{"t":"p","text":"Dieses Modell beschreibt unser betriebliches Vorgehen. Maßgeblich bleiben stets der Arbeitsvertrag und das geltende Arbeitsrecht. Details je nach Vertrag"}]},{"index":"11.6","eyebrow":"Sofortige Trennung","heading":"Wenn keine Stufe greift","blocks":[{"t":"p","text":"Bei besonders schwerem Fehlverhalten kann das 3-Stufen-Modell entfallen. Solche Verstöße können unmittelbar zur Beendigung des Arbeitsverhältnisses führen."},{"t":"box","label":"","text":"Schwere Verstöße"},{"t":"p","text":"Können zur sofortigen Trennung führen: Diebstahl · Alkohol- oder Drogenkonsum im Dienst · Gewalt oder Bedrohung · vorsätzlicher grober Hygiene- oder Halal-Verstoß · beharrliche Arbeitsverweigerung."},{"t":"box","label":"","text":"Hinweis"},{"t":"p","text":"Ob und wie eine sofortige Trennung erfolgt, richtet sich nach dem Einzelfall, dem Arbeitsvertrag und dem Arbeitsrecht. Diese Liste beschreibt die Schwere, nicht eine automatische Rechtsfolge."}]},{"index":"11.7","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Einem Mitarbeiter unterläuft ein Fehler an der Kasse."},{"t":"ul","items":["Fehler wird vertuscht","Auf Nachfrage wird gelogen","Wiederholt sich trotz Hinweis","Folge: 3-Stufen-Modell greift"]},{"t":"ul","items":["Fehler wird sofort gemeldet","Offen & ehrlich erklärt","Daraus gelernt, passiert nicht wieder","Folge: kein Problem — Teil des Lernens"]}]},{"index":"11.8","eyebrow":"Checkliste","heading":"Mein Verhalten","blocks":[{"t":"ul","items":["Ich behandle alle mit Respekt — Gäste, Team, Chefs, Lieferanten","Ich bin ehrlich und vertusche nichts","Ich melde Fehler sofort","Ich bin pünktlich und nutze das Handy nur in der Pause","Kein Alkohol, keine Drogen im Dienst","Ich halte Hygiene & Halal ausnahmslos ein"]}]},{"index":"11.9","eyebrow":"Qualitätskontrolle","heading":"Wie es dokumentiert wird","blocks":[{"t":"table","rows":[["Schritt","Verantwortlich","Festgehalten in"],["Klärendes Gespräch","Schichtleiter / Chef","Notiz"],["Schriftliche Verwarnung","Chef","Personalakte"],["Trennung","Chef","Personalakte, nach Arbeitsrecht"]]},{"t":"p","text":"Alles wird sachlich und nachvollziehbar dokumentiert — für Fairness auf beiden Seiten."}]},{"index":"11.10","eyebrow":"Fehler vermeiden","heading":"Häufige Missverständnisse","blocks":[{"t":"p","text":"Das Gegenteil stimmt. Ein gemeldeter Fehler ist kein Problem — ein vertuschter wird zu einem."},{"t":"p","text":"Regeln gelten für alle gleich — vom ersten Tag bis zum Schichtleiter."},{"t":"p","text":"Ein ehrlicher Fehler ja. Aber bewusstes Fehlverhalten zählt sofort."},{"t":"p","text":"Handynutzung im Dienst steht klar auf der Liste. Nur in der Pause."}]},{"index":"11.11","eyebrow":"Tipp vom Management","heading":"Best Practice — Ehrlichkeit zahlt sich aus","blocks":[{"t":"box","label":"","text":"Sag es einfach"},{"t":"p","text":"Wenn etwas schiefgeht, sag es sofort. Kein Chef ist über einen ehrlichen Fehler verärgert — aber jeder über einen vertuschten. Ehrlichkeit ist bei uns kein Risiko, sondern der schnellste Weg, Vertrauen aufzubauen. Die zuverlässigsten Menschen machen keine Fehler weniger — sie gehen nur ehrlicher damit um."}]},{"index":"11.12","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Fehler sind erlaubt (und werden gemeldet), Fehlverhalten nicht.","Nicht toleriert: Diebstahl, Lügen, Alkohol/Drogen, Respektlosigkeit u. a.","3 Stufen: Gespräch → schriftliche Verwarnung → Trennung.","Schwere Verstöße können zur sofortigen Trennung führen.","Alle werden gleich & fair behandelt — Arbeitsvertrag/-recht gilt."]},{"t":"p","text":"QR-Code zu Verwarnungs- & Gesprächsvorlagen. Link später ergänzen"}]}]},{"no":"12","title":"Schulung, Karriere & Abschluss","thesis":"Hier läuft alles zusammen: vom ersten Tag zur Meisterschaft. Wer die Standards lebt, wächst mit uns.","readtime":"ca. 12 Minuten","sections":[{"index":"12.1","eyebrow":"Einführung","heading":"Vom ersten Tag bis zur Meisterschaft","blocks":[{"t":"lead","text":"Niemand kann alles am ersten Tag. Deshalb hat die Einarbeitung bei uns einen klaren Weg — Schritt für Schritt, Station für Station."},{"t":"p","text":"Dieses Kapitel zeigt, wie du eingearbeitet wirst, was in der Abschlussprüfung erwartet wird und welchen Weg du bei MeatyMunch gehen kannst. Am Ende steht deine Empfangsbestätigung — der offizielle Start."}]},{"index":"12.2","eyebrow":"Ziel des Kapitels","heading":"Was du nach diesem Kapitel weißt","blocks":[{"t":"box","label":"","text":"Ziel"},{"t":"ul","items":["Wie deine Einarbeitung abläuft.","Was die Kompetenzstufen pro Station bedeuten.","Was in der Abschlussprüfung erwartet wird.","Welchen Karriereweg es bei uns gibt.","Wie du die Empfangsbestätigung unterschreibst."]}]},{"index":"12.3","eyebrow":"Der Schulungsplan","heading":"Dein Einarbeitungsweg","blocks":[{"t":"p","text":"So wächst du in deine Rolle hinein — begleitet, nie ins kalte Wasser geworfen."},{"t":"p","text":"Tag 1Ankommen & Marke verstehenHandbuch erhalten, Werte & DNA, Erscheinungsbild, Sicherheitswege im Container (Kapitel 01 & 10)."},{"t":"p","text":"Woche 1Erste Station lernenBegleitet an einer Station arbeiten, SOP-Karte lesen, Hygiene-Grundlagen anwenden (Kapitel 03 & 06)."},{"t":"p","text":"Woche 2–4Selbstständig werdenStation eigenständig führen, Service & Qualitätskontrolle beherrschen (Kapitel 05 & 07)."},{"t":"p","text":"1.–2. MonatMehrere Stationen & AbschlussWeitere Stationen lernen (Cross-Training), dann die Abschlussprüfung."}]},{"index":"12.4","eyebrow":"Kompetenzstufen","heading":"Stationen-Freigabe","blocks":[{"t":"p","text":"Für jede Station gibt es drei Stufen. Der Schichtleiter hakt ab, wenn du eine Stufe erreicht hast."},{"t":"table","rows":[["Station","Eingew.","Selbst.","Anlernen"],["Prep / Vorbereitung","","",""],["Grill / Smash","","",""],["Chicken / Fritteuse","","",""],["Fries / Loaded Fries","","",""],["Soßen / Bain-Marie","","",""],["Ausgabe / Kasse","","",""]]}]},{"index":"12.5","eyebrow":"Abschlussprüfung","heading":"Zeig, dass du bereit bist","blocks":[{"t":"p","text":"Die Prüfung ist kein Test zum Durchfallen, sondern der Nachweis, dass du die Standards sicher beherrschst — in Theorie und Praxis."},{"t":"table","rows":[["Bereich","Was geprüft wird"],["Werte & Verhalten","Kennt Mission, Werte & Regeln (Kapitel 01, 05, 11)"],["Hygiene & Sicherheit","Händehygiene, Temperaturen, Fettbrand-Regel (Kapitel 03, 10)"],["Stationen & SOP","Arbeitet sicher nach SOP an mind. einer Station (Kapitel 06)"],["Service & Qualität","Servicebogen & 5-Kriterien-Check (Kapitel 05, 07)"]]},{"t":"p","text":"Format & Bestehensgrenze legt die Geschäftsführung fest. Prüfungsbogen ergänzen"}]},{"index":"12.6","eyebrow":"Karrierepfad","heading":"Dein Weg nach oben","blocks":[{"t":"p","text":"Wir befördern von innen. Wer Verantwortung übernimmt und Standards lebt, wächst mit dem Unternehmen."},{"t":"p","text":"Beherrscht Stationen & Standards, zuverlässig & sauber."},{"t":"p","text":"Führt Schichten, kontrolliert Qualität, löst Probleme."},{"t":"p","text":"Verantwortet Standort, Zahlen & Team."},{"t":"p","text":"Führt eigenen Standort nach dem MeatyMunch-Standard."},{"t":"box","label":"","text":"Worauf wir schauen"},{"t":"p","text":"Nicht Dienstjahre entscheiden, sondern Verlässlichkeit, Haltung und Verantwortung. Wer zeigt, dass man ihm vertrauen kann, bekommt die nächste Stufe."}]},{"index":"12.7","eyebrow":"Praxisbeispiel","heading":"Vorher / Nachher","blocks":[{"t":"p","text":"Zwei neue Mitarbeiter starten am selben Tag."},{"t":"ul","items":["Wartet, bis ihm etwas gesagt wird","Fragt nicht nach, wenn etwas unklar ist","Bleibt auf einer Station","Bleibt austauschbar"]},{"t":"ul","items":["Fragt nach & lernt schnell","Nutzt die SOP-Karten aktiv","Lernt mehrere Stationen","Wird zum Kandidaten für Schichtleiter"]}]},{"index":"12.8","eyebrow":"Checkliste","heading":"Einarbeitung abgeschlossen","blocks":[{"t":"ul","items":["Handbuch gelesen & verstanden","Werte, Hygiene & Sicherheit sicher gekannt","Mind. eine Station selbstständig geführt","Service & 5-Kriterien-Check angewendet","Abschlussprüfung bestanden","Empfangsbestätigung unterschrieben"]}]},{"index":"12.9","eyebrow":"Fehler vermeiden","heading":"Häufige Fehler in der Einarbeitung","blocks":[{"t":"p","text":"Unklarheiten werden zu Fehlern. Lieber einmal zu viel fragen als raten."},{"t":"p","text":"Die Karte ist da, um sie zu nutzen. Aktiv lesen, nicht auswendig raten."},{"t":"p","text":"Wer nur eine Station kann, bleibt austauschbar. Cross-Training öffnet Türen."},{"t":"p","text":"Sie ist ein Nachweis, kein Fallstrick. Wer die Standards lebt, besteht."}]},{"index":"12.10","eyebrow":"Tipp vom Management","heading":"Best Practice — sei der, den man befördern will","blocks":[{"t":"box","label":"","text":"Die einfache Formel"},{"t":"p","text":"Sei zuverlässig, sei sauber, sei freundlich — jeden Tag. Übernimm Aufgaben, bevor man dich fragt. Genau diese Menschen fallen auf und steigen auf. Deine Karriere beginnt nicht mit der Beförderung, sondern mit der Art, wie du heute deine Schicht machst."}]},{"index":"12.11","eyebrow":"Zusammenfassung","heading":"Das Wichtigste in Kürze","blocks":[{"t":"ul","items":["Einarbeitung Schritt für Schritt: Tag 1 → Woche 1 → selbstständig → Abschluss.","Drei Kompetenzstufen: eingewiesen → selbstständig → kann anlernen.","Die Abschlussprüfung weist Werte, Hygiene, SOP & Service nach.","Karriere von innen: Mitarbeiter → Schichtleiter → Restaurantleiter → Franchise.","Der Abschluss ist die unterschriebene Empfangsbestätigung."]}]},{"index":"12.12","eyebrow":"Empfangsbestätigung","heading":"Deine Unterschrift","blocks":[{"t":"p","text":"Mit deiner Unterschrift bestätigst du, dass du das Handbuch erhalten, gelesen und verstanden hast. Eine Ausfertigung kommt in die Personalakte, eine behältst du."},{"t":"p","text":"Hiermit bestätige ich, dass ich das MeatyMunch Mitarbeiterhandbuch – Band 1 erhalten, vollständig gelesen und verstanden habe. Ich verpflichte mich, die darin beschriebenen Standards, Werte und Regeln einzuhalten."},{"t":"ul","items":["Ich habe die Werte & Verhaltensregeln verstanden (Kap. 01, 05, 11).","Ich habe Hygiene & Lebensmittelsicherheit verstanden (Kap. 03).","Ich habe Notfälle & Arbeitsschutz verstanden (Kap. 10).","Ich kenne das 3-Stufen-Konsequenzmodell (Kap. 11)."]},{"t":"p","text":"QR-Code zu Schulungsplan, Prüfungsbogen & Kompetenz-Tracker. Link später ergänzen"}]}]}];
